var documenterSearchIndex = {"docs":
[{"location":"references/#References","page":"References","title":"References","text":"","category":"section"},{"location":"references/","page":"References","title":"References","text":"(Bathe, 2014) Klaus-Jurgen Bathe.  Finite Element Procedures . 2014.\n(Bazzano and Pérez Zerpa, 2017) J. B. Bazzano and J. Perez Zerpa.  Introducción al Análisis No Lineal de Estructuras. 2017.\n(Battini and Pacoste, 2002) Co-rotational beam elements with warping effects in instability problems, Computer Methods in Applied Mechanics and Engineering, 191 (17-18). 2020.\n(Holzapfel, 2000) Nonlinear Solid Mechanics, A continuum approach for Engineering, 2000, Wiley.","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"% Copyright 2024, ONSAS Authors (see documentation) % % This file is part of ONSAS. % % ONSAS is free software: you can redistribute it and/or modify % it under the terms of the GNU General Public License as published by % the Free Software Foundation, either version 3 of the License, or % (at your option) any later version. % % ONSAS is distributed in the hope that it will be useful, % but WITHOUT ANY WARRANTY; without even the implied warranty of % MERCHANTABILITY or FITNESS FOR A PARTICULAR PURPOSE.  See the % GNU General Public License for more details. % % You should have received a copy of the GNU General Public License % along with ONSAS.  If not, see https://www.gnu.org/licenses/. %","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"# Spring-mass-damper system example\n\n[![Octave script](https://img.shields.io/badge/script-url-blue)](https://github.com/ONSAS/ONSAS/blob/master/examples/springMass/springMass.m)\n\n## ODE System definition\nIn this example a simple spring-mass-damper system is considered. This simple problem is used to validate different implementations of truss and frame elements submitted to dynamic loads.\n","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"@raw html <img src=\"../../assets/springMassSystem.svg\" alt=\"spring-mass diagram\" width=\"800\"/>","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"## Analytic solution\nThe analytical solution is based on chapter 3 from _Dynamics of Structures_ by Ray W. Clough and Joseph Penzien, Third Edition, 2003.\nThe analytical solution of the problem is given by:","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"math   u(t) =      \\left( Ac \\cos( \\omegaD  t ) + B \\sin( \\omegaD t )  \\right) e^{ -\\xi \\omegaN t } +     G1  \\cos( \\bar{\\omega} t ) + G2 \\sin( \\bar{\\omega} t )","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":" where the notation and the parameters interpretation can be seen in the cited reference.\n\nA set of numerical parameters must be defined to compute the analytic solution.\n\n We start as all models, clearing the workspace and adding the ONSAS path to the work path.","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"% clear workspace and add path close all; if ~strcmp(getenv('TESTS_RUN'), 'yes')   clear all; end % addpath(genpath([pwd '/../../src']));","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":" The following numeric parameters are considered.","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"% scalar parameters for spring-mass system k    = 39.47; % spring constant c    = 2; % damping parameter m    = 1; % mass of the system p0   = 40; % amplitude of applied load u0   = 0.1; % initial displacement du0  = 0.0; % initial velocity","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"\n Then other parameters are computed:\n","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"omegaN  = sqrt(k / m); % the natural frequency xi      = c / m  / (2 * omegaN); freq    = omegaN / (2 * pi); TN      = 2 * pi / omegaN; dtCrit  = TN / pi;","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"\n The frequency of the sinusoidal external force is set as:","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"omegaBar = 4 * omegaN;","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"\n The analytic solution can be computed for specific cases as follows:","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"if (c == 0) && (p0 == 0) % free undamped solution   myAnalyticFunc = @(t)   (u0 * cos(omegaN * t)); else                     % other cases solution   beta   = omegaBar / omegaN;   omegaD = omegaN * sqrt(1 - xi^2); % forced and damped   G1 = (p0 / k) * (-2 * xi * beta) / ((1 - beta^2)^2 + (2 * xi * beta)^2);   G2 = (p0 / k) * (1      - beta^2) / ((1 - beta^2)^2 + (2 * xi * beta)^2);","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"Ac = u0 - G1;   B = (xi * omegaN * Ac - omegaBar * G2) / (omegaD);","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"myAnalyticFunc = @(t) ...       (Ac * cos(omegaD   * t) + B  * sin(omegaD   * t)) .* exp(-xi * omegaN * t) + ...       G1  * cos(omegaBar * t) + G2 * sin(omegaBar * t);","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"end","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"\n## Numerical solutions\n\n The analytic solution is used to validate two numerical solution approaches using different structural physical models, governed by the same ODE.\n\n### Numerical case 1: truss element model with Newmark method and lumped masses\n\nIn this case, a truss element is considered, as shown in the figure, with Young modulus, cross-section, area, mass, nodal damping and length corresponding to the parameters considered for the spring-mass-damper system","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"@raw html <img src=\"../../assets/springMassTrussModel.svg\" alt=\"spring-mass diagram\" width=\"800\"/>","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"\n The scalar parameters for the equivalent truss model are:","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"l   = 10; A   = 0.2; rho = m * 2 / (A * l); E   = k * l /   A;","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":" where the material of the truss was selected to set a mass $m$ at the node $2$.\n","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"assert(u0 < l, 'this analytical solution is not valid for this u0 and l0');","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"\n#### Materials\n","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"materials                    = struct(); materials(1).modelName  = 'elastic-rotEngStr'; materials(1).modelParams = [E 0]; materials(1).density         = rho;","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"\n#### Elements\n\n In this case only `'node'` and  `'truss'` elements are considered and the lumped inertial formulation is set for the truss element:","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"elements             = struct(); elements(1).elemType = 'node'; elements(2).elemType = 'truss'; elements(2).elemCrossSecParams = {'circle', [sqrt(4 * A / pi)] }; elements(2).massMatType = 'lumped';","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"\n#### Boundary conditions\n\n The node $1$ is fixed, so the boundary condition set is:","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"boundaryConds                  = struct(); boundaryConds(1).imposDispDofs =  [1 3 5]; boundaryConds(1).imposDispVals =  [0 0 0];","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":" The node $2$ allows the truss to move in $x$ so the boundary condition set is:","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"boundaryConds(2).imposDispDofs =  [3 5]; boundaryConds(2).imposDispVals =  [0 0];","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":" ant the external load is added into the same boundary condition using:","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"boundaryConds(2).loadsCoordSys = 'global'; boundaryConds(2).loadsTimeFact = @(t) p0 * sin(omegaBar * t); boundaryConds(2).loadsBaseVals = [1 0 0 0 0 0];","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"\n#### Initial conditions\n Initial displacement and velocity are set:","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"aux = zeros(6 * 2, 1); aux(7) = u0; initialConds.U = aux; aux(7) = du0; initialConds.Udot = aux;","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"\n#### Analysis settings\n The following parameters correspond to the iterative trapezoidal Newmark method with the following tolerances, time step, tolerances and final time","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"analysisSettings               = struct(); analysisSettings.methodName    = 'newmark'; analysisSettings.deltaT        =   0.005; analysisSettings.finalTime     =   2.5 * TN; analysisSettings.stopTolDeltau =   1e-10; analysisSettings.stopTolForces =   1e-10; analysisSettings.stopTolIts    =   10;","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"\n#### OtherParams\n The nodalDispDamping is added into the model using:","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"otherParams                  = struct(); otherParams.nodalDispDamping = c;","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":" The name of the problem is:\n","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"otherParams.problemName = 'springMass_case1';","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"\n### mesh\n Only two nodes are considered so the nodes matrix is:","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"mesh             = struct(); mesh.nodesCoords = [0  0  0; ...                     l  0  0]; mesh.conecCell = { }; % The first node has no material, the first element of the elements struct, which is 'node' also the first boundary condition (fixed) and no initial condition is set. mesh.conecCell{ 1, 1 } = [0 1 1    1]; % The second node has no material, the first element of the elements struct, which is 'node' also the second boundary condition (x disp free) and the first initial condition (u_0) is set. mesh.conecCell{ 2, 1 } = [0 1 2    2]; % Only one element is considered with the first material and the second element setting mesh.conecCell{ 3, 1 } = [1 2 0    1 2];","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"\n Execute ONSAS and save the results:","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"[modelCurrSol, modelProperties, BCsData] = ONSAS_init(materials, elements, boundaryConds, initialConds, mesh, analysisSettings, otherParams); %","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"After that the structs are used to perform the numerical time analysis","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"[matUsNewmark, loadFactorsMat, modelSolutions] = ONSAS_solve(modelCurrSol, modelProperties, BCsData);","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"\n### Numerical case 2: truss model with nodal masses, using $\\alpha$-HHT method and user loads function\n\n#### Material\n The nodalMass field allows to add lumped matrices to a node, since this field is used, then the equivalent $\\rho$ of the `material(1)` aforementioned now is set to 0. Although an equal mass $m$ is considered for $u_x$ $u_y$ and $u_z$ at the node $2$, so:","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"materials(1).density   = 0; materials(2).nodalMass = [m m m];","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"\n#### Boundary conditions\n the boundary conditions struct is entirely re-written.","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"% repeat the BCs for node 1 boundaryConds                  = { }; boundaryConds(1).imposDispDofs =  [1 3 5]; boundaryConds(1).imposDispVals =  [0 0 0]; % repeat the BCs for node 2 boundaryConds(2).imposDispDofs =  [3 5]; boundaryConds(2).imposDispVals =  [0 0];","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":" ant the external load is added into the same boundary condition using:","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"boundaryConds(3).userLoadsFilename = 'myLoadSpringMass';","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":" where inside the function 'myLoadSpringMass' the external force vector of the structure with 12 = (2x6) entries is computed.\n\n now the initial condition is added to the node $2$ with the second material:","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"mesh.conecCell{ 2, 1 } = [2 1 2   2];","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"\n The $\\alpha_{HHT}$ method with $\\alpha=0$ is equivalent to Newmark, this is employed to validate results of both methods, then:","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"analysisSettings.methodName = 'alphaHHT'; analysisSettings.alphaHHT   =   0;","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"otherParams.problemName = 'springMass_case2';","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"\n Execute ONSAS and save the results:","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"[modelCurrSol, modelProperties, BCsData] = ONSAS_init(materials, elements, boundaryConds, initialConds, mesh, analysisSettings, otherParams); %","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"After that the structs are used to perform the numerical time analysis","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"[matUsHHT, loadFactorsMat, modelSolutions] = ONSAS_solve(modelCurrSol, modelProperties, BCsData);","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"\n\n### Numerical case 3: beam element model\n","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"d = l / 10; A   = pi * d^2 /  4; Izz = pi * d^4 / 64; E   = k * l^3 / (3 * Izz); % delta = P L3/(3EI)  =>  k = P/delta = 3EI/L3  => E = kL3/(3I) rho = 2 * m / (A * l);","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"materials(1).modelParams = [E 0]; materials(1).density  = rho; materials(1).modelName  = 'elastic-linear'; % elastic-rotEngStr should work as well","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"elements             = {}; elements(1).elemType = 'node'; elements(2).elemType = 'frame'; % and not truss elements(2).massMatType = 'lumped'; elements(2).elemCrossSecParams{1, 1} = 'circle'; elements(2).elemCrossSecParams{2, 1} = [d]; elements(2).elemTypeParams = 0;","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"boundaryConds = {}; boundaryConds(1).imposDispDofs =  [1 2 3 4 5 6]; boundaryConds(1).imposDispVals =  [0 0 0 0 0 0];","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"boundaryConds(2).loadsCoordSys = 'global'; boundaryConds(2).loadsTimeFact = @(t) p0 * sin(omegaBar * t); boundaryConds(2).loadsBaseVals = [0 0 1 0 0 0]; % along Y axis","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"mesh.nodesCoords = [0  0  0; ...                     l  0  0]; mesh.conecCell = { }; mesh.conecCell{ 1, 1 } = [0 1 1    1]; mesh.conecCell{ 2, 1 } = [0 1 2    2]; mesh.conecCell{ 3, 1 } = [1 2 0    1 2];","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"\n An initial displacements $u_0$ is set in $y$ direction:","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"aux = zeros(6 * 2, 1); aux(6 + 3) = u0; initialConds.U = aux; aux(6 + 3) = du0; initialConds.Udot = aux;","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"otherParams.problemName = 'springMass_case3';","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"analysisSettings.methodName    = 'newmark';","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"[modelCurrSol, modelProperties, BCsData] = ONSAS_init(materials, elements, boundaryConds, initialConds, mesh, analysisSettings, otherParams); %","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"After that the structs are used to perform the numerical time analysis","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"[matUsBending, loadFactorsMat, modelSolutions] = ONSAS_solve(modelCurrSol, modelProperties, BCsData);","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"valsBending = matUsBending(6 + 3, :);","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"\n## Verification\n The numerical displacements of the node $2$ is extracted for both study cases:","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"valsNewmark = matUsNewmark(6 + 1, :); valsHHT     = matUsHHT(6 + 1, :);","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":" The analytical solution is evaluated:","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"times       = linspace(0, analysisSettings.finalTime, size(matUsHHT, 2)); valsAnaly   = myAnalyticFunc(times);","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":" The boolean to validate the implementation is evaluated such as:","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"analyticCheckTolerance = 5e-2; verifBooleanNewmark =  ((norm(valsAnaly  - valsNewmark) / norm(valsAnaly)) <  analyticCheckTolerance); verifBooleanHHT     =  ((norm(valsAnaly  - valsHHT) / norm(valsAnaly)) <  analyticCheckTolerance); verifBooleanBending =  ((norm(valsBending - valsHHT) / norm(valsAnaly)) <  analyticCheckTolerance); verifBoolean        = verifBooleanHHT && verifBooleanNewmark && verifBooleanBending;","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"\n\n## Plot verification\n\n The control displacement $u(t)$ is plotted:","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"figure; hold on; grid on; spanPlot = 8; lw = 2.0; ms = 11; plotfontsize = 20; plot(times, valsAnaly, 'b-', 'linewidth', lw, 'markersize', ms); plot(times(1:spanPlot:end), valsNewmark(1:spanPlot:end), 'ro', 'linewidth', lw, 'markersize', ms); plot(times(1:spanPlot:end), valsHHT(1:spanPlot:end), 'gs', 'linewidth', lw, 'markersize', ms); plot(times(1:spanPlot:end), valsBending(1:spanPlot:end), 'yx', 'linewidth', lw, 'markersize', ms); labx = xlabel('t [s]'); laby = ylabel('u(t) [m]'); legend('analytic', 'truss-Newmark', 'nodalMass-HHT', 'Beam-model', 'location', 'northeast'); title(sprintf('dt = %.3d, m = %d, c = %d, k = %d, p0 = %d', analysisSettings.deltaT, m, c, k, p0)); set(gca, 'linewidth', 1.0, 'fontsize', plotfontsize); set(labx, 'FontSize', plotfontsize); set(laby, 'FontSize', plotfontsize); print('output/springMassCheckU.png', '-dpng');","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"","category":"page"},{"location":"examples/springMass/","page":"Spring-mass system","title":"Spring-mass system","text":"@raw html <img src=\"../../assets/generated/springMassCheckU.png\" alt=\"plot check\" width=\"500\"/> ```","category":"page"},{"location":"install/#Installation","page":"Installation","title":"Installation","text":"","category":"section"},{"location":"install/#Running-ONSAS","page":"Installation","title":"Running ONSAS","text":"","category":"section"},{"location":"install/","page":"Installation","title":"Installation","text":"The user should follow these steps to install and run ONSAS:","category":"page"},{"location":"install/","page":"Installation","title":"Installation","text":"Download and install the latest version of GNU-Octave.\nDownload the zip file of the latest ONSAS release from these site.\nOpen GNU-Octave and run one of the example scripts from the examples folder (or create yours!).","category":"page"},{"location":"install/#Visualizing-results","page":"Installation","title":"Visualizing results","text":"","category":"section"},{"location":"install/","page":"Installation","title":"Installation","text":"You can process the outputs using Octave, however, the open-source software ParaView can be used to visualize the results produced by ONSAS.","category":"page"},{"location":"install/#Generation-of-geometries/meshes","page":"Installation","title":"Generation of geometries/meshes","text":"","category":"section"},{"location":"install/","page":"Installation","title":"Installation","text":"The user can provide the geometry of the structure using two optional formats: .msh or .dxf.  GMSH is an open-source tool that allows to generate high-quality meshes. The dxf files can be used using any CAD tool.","category":"page"},{"location":"install/#Development-tools","page":"Installation","title":"Development tools","text":"","category":"section"},{"location":"install/","page":"Installation","title":"Installation","text":"If you want to contribute you should install python -> poetry -> miss-hit, to check the styling of the code before pushing. It is recommended but not mandatory to install poetry in a specific directory doing this in linux's bash or whatever corresponds to you OS: ","category":"page"},{"location":"install/","page":"Installation","title":"Installation","text":"cd ONSAS/utils\npython -m venv .venv\nsource .venv/bin/activate","category":"page"},{"location":"install/","page":"Installation","title":"Installation","text":"Then install poetry, install miss-hit and check","category":"page"},{"location":"install/","page":"Installation","title":"Installation","text":"pip install poetry\nmake install\nmake format_check","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"% Copyright 2024, ONSAS Authors (see documentation) % % This file is part of ONSAS. % % ONSAS is free software: you can redistribute it and/or modify % it under the terms of the GNU General Public License as published by % the Free Software Foundation, either version 3 of the License, or % (at your option) any later version. % % ONSAS is distributed in the hope that it will be useful, % but WITHOUT ANY WARRANTY; without even the implied warranty of % MERCHANTABILITY or FITNESS FOR A PARTICULAR PURPOSE.  See the % GNU General Public License for more details. % % You should have received a copy of the GNU General Public License % along with ONSAS.  If not, see https://www.gnu.org/licenses/. %","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"# Uniform curvature cantilever beam example\n---\n\nIn this tutorial, the Uniform curvature cantilever example and its resolution using ONSAS are described. The aim of this example is to validate the static co-rotational 3D beam implementation by comparing the results provided by ONSAS with the analytical solution.  The Octave script of this example is available at [this url](https://github.com/ONSAS/ONSAS/blob/master/examples/uniformCurvatureCantilever/onsasExample_uniformCurvatureCantilever.m).\n\nThe problem consists in a beam, with one free end (right) submitted to a nodal moment $M$, and the other end (left) constrained (welded), as it is shown in the figure.\n","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"@raw html <img src=\"../../assets/cantileverBeam_HTML.svg\" alt=\"structure diagram\" width=\"500\"/>","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"\nBefore defining the structs, the workspace is cleaned, the ONSAS directory is added to the path and scalar geometry and material parameters are defined.","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"close all; if ~strcmp(getenv('TESTS_RUN'), 'yes')   clear all; end % add path addpath(genpath([pwd '/../../src'])); % material scalar parameters E = 200e9; nu = 0.3; % geometrical scalar parameters l = 10; ty = .1; tz = .1; % the number of elements of the mesh numElements = 10;","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"\n## Analytic solution\n The rotation of the right end, for a given moment $M$, can be computed as:","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"math  M( \\theta ) = E I_y \\frac{ \\theta}{ l }  ;","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"## Numerical solution\n### MEB parameters\n\nThe modelling of the structure begins with the definition of the Material-Element-BoundaryConditions (MEB) parameters.\n\n### materials\n Since the example contains only one rod the fields of the `materials` struct will have only one entry. Although, it is considered constitutive behavior according to the SaintVenantKirchhoff law:","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"materials                 = struct(); materials.modelName  = 'elastic-rotEngStr'; materials.modelParams = [E nu];","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":" The density is not defined, therefore it is considered as zero (default), then no inertial effects are considered (static analysis).\n\n### elements\n\nTwo different types of elements are considered, node and beam. The nodes will be assigned in the first entry (index $1$) and the beam at the index $2$. The elemType field is then:","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"elements             = struct(); elements(1).elemType = 'node'; elements(2).elemType = 'frame';","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":" for the geometries, the node has not geometry to assign (empty array), and the truss elements will be set as a rectangular-cross section with $t_y$ and $t_z$ cross-section dimensions in $y$ and $z$ directions, then the elemCrossSecParams field is:","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"elements(2).elemCrossSecParams{1, 1} = 'rectangle'; elements(2).elemCrossSecParams{2, 1} = [ty tz];","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"\n### boundaryConds\n\n The elements are submitted to two different BC settings. The first BC corresponds to a welded condition (all 6 dofs set to zero)","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"Iy = ty * tz^3 / 12; boundaryConds                  = struct(); boundaryConds(1).imposDispDofs = [1 2 3 4 5 6]; boundaryConds(1).imposDispVals = [0 0 0 0 0 0];","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"and the second corresponds to an incremental nodal moment, where the target load produces a circular form of the deformed beam.","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"boundaryConds(2).loadsCoordSys = 'global'; boundaryConds(2).loadsTimeFact = @(t) E * Iy * 2 * pi / l * t; boundaryConds(2).loadsBaseVals = [0 0 0 -1 0 0];","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"\n\n### initial Conditions\n homogeneous initial conditions are considered, then an empty cell is set:","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"initialConds = {};","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"\n### mesh parameters\nThe coordinates of the nodes of the mesh are given by the matrix:","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"mesh             = struct(); mesh.nodesCoords = [(0:(numElements))' * l / numElements  zeros(numElements + 1, 2)];","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"The connectivity is introduced using the _conecCell_. Each entry of the cell contains a vector with the four indexes of the MEB parameters, followed by the indexes of the nodes of the element (node connectivity). For didactical purposes each element entry is commented. First the cell is initialized:","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"mesh.conecCell = { };","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":" then the first two nodes are defined, both with material zero (since nodes dont have material), the first element type (the first entry of the cells of the _elements_ struct), and the first entry of the cells of the boundary conditions struct. Finally the node is included.","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"mesh.conecCell{ 1, 1 } = [0 1 1   1];","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":" the following case only differs in the boundary condition and the node number","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"mesh.conecCell{ 2, 1 } = [0 1 2   numElements + 1];","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":" the beam elements are formed by the first material, the second type of element, and no boundary conditions are applied to any element.","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"for i = 1:numElements   mesh.conecCell{ i + 2, 1 } = [1 2 0  i i + 1]; end","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"\n### analysisSettings","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"analysisSettings               = struct(); analysisSettings.methodName    = 'newtonRaphson'; analysisSettings.deltaT        =   0.1; analysisSettings.finalTime      =   1; analysisSettings.stopTolDeltau =   1e-6; analysisSettings.stopTolForces =   1e-6; analysisSettings.stopTolIts    =   10;","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"\n## otherParams","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"otherParams             = struct(); otherParams.problemName = 'uniformCurvatureCantilever'; otherParams.controlDofs = [numElements + 1  4]; otherParams.plots_format = 'vtk';","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"## Analysis case 1: NR with Rotated Eng Strain\n In the first case ONSAS is run and the solution at the dof (angle of node B) of interest is stored:","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"[modelCurrSol, modelProperties, BCsData] = ONSAS_init(materials, elements, boundaryConds, initialConds, mesh, analysisSettings, otherParams); %","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"After that the structs are used to perform the numerical time analysis","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"[matUs, loadFactorsMat, modelSolutions] = ONSAS_solve(modelCurrSol, modelProperties, BCsData);","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"\n the control dof to verificate the solution is the node angle B, this corresponds to the following dof number:","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"angleControlDof      = (numElements + 1) * 6 - 2; controlDispsNREngRot =  -matUs(angleControlDof, :); loadFactorsNREngRot  =  loadFactorsMat(:, 2);","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":" and the analytical value of the load factors is computed","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"analyticLoadFactorsNREngRot = @(w) E * Iy * w / l;","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"\n## Verification\n","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"verifBoolean = norm(analyticLoadFactorsNREngRot(controlDispsNREngRot) - loadFactorsNREngRot')                    < (norm(analyticLoadFactorsNREngRot(controlDispsNREngRot)) * 1e-4);","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"\n","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"lw = 2.0; ms = 11; plotfontsize = 22; figure; plot(controlDispsNREngRot, analyticLoadFactorsNREngRot(controlDispsNREngRot), 'b-x', 'linewidth', lw, 'markersize', ms); hold on; grid on; plot(controlDispsNREngRot, loadFactorsNREngRot, 'k-o', 'linewidth', lw, 'markersize', ms); labx = xlabel('Displacement'); laby = ylabel('lambda'); legend('analytic', 'NR-RotEng', 'location', 'North'); set(gca, 'linewidth', 1.2, 'fontsize', plotfontsize); set(labx, 'FontSize', plotfontsize); set(laby, 'FontSize', plotfontsize); print('output/verifCantileverBeam.png', '-dpng');","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"@raw html <img src=\"../../assets/verifCantileverBeam.png\" alt=\"plot check\" width=\"500\"/>","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"\n","category":"page"},{"location":"examples/cantileverBeam/","page":"Cantilever Beam","title":"Cantilever Beam","text":"verifBoolean = norm(analyticLoadFactorsNREngRot(controlDispsNREngRot) - loadFactorsNREngRot')  < (norm(analyticLoadFactorsNREngRot(controlDispsNREngRot)) * 1e-4); ```","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"% Copyright 2024, ONSAS Authors (see documentation) % % This file is part of ONSAS. % % ONSAS is free software: you can redistribute it and/or modify % it under the terms of the GNU General Public License as published by % the Free Software Foundation, either version 3 of the License, or % (at your option) any later version. % % ONSAS is distributed in the hope that it will be useful, % but WITHOUT ANY WARRANTY; without even the implied warranty of % MERCHANTABILITY or FITNESS FOR A PARTICULAR PURPOSE.  See the % GNU General Public License for more details. % % You should have received a copy of the GNU General Public License % along with ONSAS.  If not, see https://www.gnu.org/licenses/. %","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"# Simple Propeller example\nIn this example a simple propeller problem, inspired in an example [this article](https://doi.org/10.1016/j.heliyon.2023.e19990), is considered.\n","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"close all; if ~strcmp(getenv('TESTS_RUN'), 'yes')   clear all;","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"\n## Problem definition\n\nThe propeller has three blades with circular cross section and a uniform constant fluid flow is assumed as shown in the figure. Only lift is considered.\n","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"@raw html <img src=\"../../assets/diagprop.png\" alt=\"plot check\" width=\"600\"/>","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"\nThe wind velocity is assumed constant and uniform, given by the function `windVel.m` with one argument (time), located in the same folder. Then the fluid velocity is computed as:","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"va = feval('windVel', 0, 0);","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"\nThe density and kinematic viscosity are set:","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"rhoA = 1.225; nuA = 1.6e-5;","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"The blades are considered to have only lift, with a lift coefficient given by the function `liftCoef.m` placed in the same folder.","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"c_l = feval('liftCoef', 0);","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"The material parameters of the blades correspond to steel with Young modulus, Poisson coefficient and density given by:","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"E = 210e9; nu = 0.3; rho = 6000;","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"and the geometric parameters of the blades for length and diameter are set as:","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"l = 3; d = 0.1;","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"\n## Analytical solution\nSince only lift is considered, an analytical solution can be computed. The the lift load per unit of length is obtained as:","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"fl = 1 / 2 * c_l * rhoA * norm(va)^2 * d;","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":" the total moment $M_x$ in node 1 is given by the sum of the moments for the three blades:","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"moment1x = 3 * fl * l * l / 2;","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"and then the angular moment is:","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"bladeMass = rho * l * pi * d^2 / 4; Jrho =  3 * 1 / 3 * bladeMass  * l^2;","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":" Then, integrating, the angle $\\theta_x$ can be obtained as a function of time.","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"angleXnode1 = @(t)  moment1x / Jrho / 2 * t.^2;","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"\nIf the blades are considered stiff enough and only lift is considered, this rigid-rotation solution can be used to verify the numerical solution.\n\n## Numerical solution\n\nSet the material parameters:","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"materials             = struct(); materials.modelName   = 'elastic-rotEngStr'; materials.modelParams = [E nu]; materials.density     = rho;","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"\n### elements\nThe elements are given by: nodes","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"elements             = struct(); elements(1).elemType = 'node';","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"frame elements for modelling the blades","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"elements(2).elemType = 'frame'; elements(2).elemCrossSecParams = {'circle'; d }; elements(2).massMatType =  'consistent';","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":" with the definition of the aerodynamic forces","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"elements(2).aeroCoefFunctions = {@(beta, Re) 0, 'liftCoef', @(beta, Re) 0};","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":" and a auxiliar truss element for the pole","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"elements(3).elemType = 'truss'; elements(3).elemCrossSecParams = {'circle'; 1.5 * d }; elements(3).massMatType =  'lumped';","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"\n### boundary Conditions\n The only boundary condition is the one of the center node, with all the dofs fixed except for the rotation $\\theta_x$","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"boundaryConditions             = struct(); boundaryConds(1).imposDispDofs = [1 3 4 5 6]; boundaryConds(1).imposDispVals = [0 0 0 0 0];","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"\n### mesh\n The mesh is defined","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"mesh             = struct(); mesh.nodesCoords = [0        0              0; ...                     0  l * sin(pi)        l * cos(pi); ...                     0  l * sin(pi / 3)     l * cos(pi / 3); ...                     0  l * sin(4 * pi / 3)   -l * cos(4 * pi / 3); ...                     -d * .75 0 d; ...                     -d * .75 0 -l * 1.5];","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":" And a simple connectivity is required since only one frame element is used for each blade","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"mesh.conecCell         = { }; mesh.conecCell{ 1, 1 } = [0 1 1   1]; mesh.conecCell{ 2, 1 } = [1 2 0   1 2]; mesh.conecCell{ 3, 1 } = [1 2 0   1 3]; mesh.conecCell{ 4, 1 } = [1 2 0   1 4];","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":" These are auxiliar elements (nodes and truss) used to model the pole","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"mesh.conecCell{ 5, 1 } = [0 1 1   5]; mesh.conecCell{ 6, 1 } = [0 1 1   6]; mesh.conecCell{ 7, 1 } = [1 3 0   5 6];","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"\n### initial Conditions\n\nhomogeneous initial conditions are considered, then an empty struct is set:","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"initialConds = struct();","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"\n### analysisSettings\n The analysis settings are set","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"analysisSettings                        = struct(); analysisSettings.finalTime              =   400; analysisSettings.deltaT                 =   5; analysisSettings.methodName             = 'alphaHHT'; analysisSettings.stopTolIts             =   50; analysisSettings.geometricNonLinearAero = true; analysisSettings.stopTolDeltau          =   0; analysisSettings.stopTolForces          =   1e-5; analysisSettings.fluidProps = { rhoA; nuA; 'windVel' };","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"\n### otherParams\n","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"otherParams = struct(); otherParams.problemName =  'simplePropeller'; otherParams.plots_format = 'vtk';","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"\n### Run ONSAS","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"[modelCurrSol, modelProperties, BCsData] = ONSAS_init(materials, elements, boundaryConds, initialConds, mesh, analysisSettings, otherParams); %","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"After that the structs are used to perform the numerical time analysis","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"[matUs, loadFactorsMat, modelSolutions] = ONSAS_solve(modelCurrSol, modelProperties, BCsData);","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"\n## Verification\n\n numerical time vector is given by:","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"timeVec = linspace(0, analysisSettings.finalTime, size(matUs, 2));","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":" numerical rotation is obtained from the ONSAS matUs:","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"dofAngleXnode1 = 2; angleXnode1Numeric = -matUs(dofAngleXnode1, :);","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"The analytic rotation is:","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"angleXnode1Analytic = angleXnode1(timeVec);","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":" and the norm of the difference is computed and the test is verified","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"verifBoolean = norm(angleXnode1Numeric - angleXnode1Analytic) < (norm(angleXnode1Analytic) * 5e-2);","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"\n## Plots\n","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"lw = 2.0; ms = 10; plotfontsize = 22; spanPlotTime = 2; fig1 = figure; plot(timeVec(1:spanPlotTime:end), angleXnode1Analytic(1:spanPlotTime:end), 'b-x', 'linewidth', lw, 'markersize', ms); hold on; grid on; plot(timeVec(1:spanPlotTime:end), angleXnode1Numeric(1:spanPlotTime:end), 'ko', 'linewidth', lw, 'markersize', ms); labx = xlabel('time(s)'); laby = ylabel('\\thetax node 1'); legend('analytic', 'numeric', 'location', 'North'); set(gca, 'linewidth', 1.2, 'fontsize', plotfontsize); set(labx, 'FontSize', plotfontsize); set(laby, 'FontSize', plotfontsize); title('simple propeller test'); if length(getenv('TESTSRUN')) > 0 && strcmp(getenv('TESTS_RUN'), 'yes')   fprintf('\\ngenerating output png for docs.\\n');   print(fig1, 'output/verifPropeller.png', '-dpng'); else   fprintf('\\n === NOT in docs workflow. ===\\n'); end","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"@raw html <img src=\"../../assets/generated/verifPropeller.png\" alt=\"plot check\" width=\"500\"/>","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"\nThe obtained simulation is:","category":"page"},{"location":"examples/simplePropeller/","page":"Propeller model","title":"Propeller model","text":"@raw html <img src=\"https://github.com/ONSAS/ONSAS/blob/master/docs/src/assets/propeller.gif?raw=true\" alt=\"propeller animation\"> ```","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"% Copyright 2024, ONSAS Authors (see documentation) % % This file is part of ONSAS. % % ONSAS is free software: you can redistribute it and/or modify % it under the terms of the GNU General Public License as published by % the Free Software Foundation, either version 3 of the License, or % (at your option) any later version. % % ONSAS is distributed in the hope that it will be useful, % but WITHOUT ANY WARRANTY; without even the implied warranty of % MERCHANTABILITY or FITNESS FOR A PARTICULAR PURPOSE.  See the % GNU General Public License for more details. % % You should have received a copy of the GNU General Public License % along with ONSAS.  If not, see https://www.gnu.org/licenses/. %","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"# Static Von-Mises Truss example\n\n[![Octave script](https://img.shields.io/badge/script-url-blue)](https://github.com/ONSAS/ONSAS/blob/master/examples/staticVonMisesTruss/staticVonMisesTruss.m)\n\nIn this example the Static Von Mises Truss problem and its resolution using ONSAS are described. The aim of this example is to verify the implementations of the Newton-Raphson and Newton-Raphson-Arc-Length methods by comparing the results provided with the analytic solutions.\n\nThe structural model is formed by two truss elements with length $L$ as it is shown in the figure, with nodes $1$ and $3$ fixed, and node $2$ submitted to a nodal load $P$ and constrained to move only in the $x-z$ plane.\n","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"@raw html <img src=\"../../assets/vonMisesTruss.svg\" alt=\"von-mises truss structure diagram\" width=\"500\"/>","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"\n## Analytic solutions\n\nThe solutions for the nonlinear cases are developed in section 2.3 of [(Bazzano and Pérez Zerpa, 2017)](https://www.colibri.udelar.edu.uy/jspui/bitstream/20.500.12008/22106/1/Bazzano_P%c3%a9rezZerpa_Introducci%c3%b3n_al_An%c3%a1lisis_No_Lineal_de_Estructuras_2017.pdf#section.2.3). The expressions obtained for different strain measures are:\n * Rotated-Engineering: $P = \\dfrac{EA_o(z_2+w)\\left(\\sqrt{(w+z_2)^2+x_2^2}-l_o\\right)}{l_o\\sqrt{(w+z_2)^2+x_2^2}}$\n * SVK: $P = \\dfrac{EA_o (z_2+w)\\left( 2 z_2 w + w^2 \\right) }{ 2 l_o^3 }$\n where $x_2$ and $z_2$ are the coordinates of node 2 in the reference configuration and $w$ is the vertical displacement in the $z$ direction.\n\n## Numerical solutions\n\nBefore defining the structs, the workspace is cleared, the ONSAS directory is added to the path %hidden","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"close all; if ~strcmp(getenv('TESTS_RUN'), 'yes')   clear all;","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":" First some scalar parameters are defined and computed","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"% scalar parameters E = 210e9; nu = 0; A = 2.5e-3; ang1 = 65; L = 2; % x and z coordinates of node 2 x2 = cos(ang1 * pi / 180) * L; z2 = sin(ang1 * pi / 180) * L;","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"\n### MEB parameters\n\nThe modelling of the structure begins with the definition of the Material-Element-BoundaryConditions (MEB) parameters.\n\n#### materials\nThe `materials` struct is initialized as empty.","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"materials                 = {};","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":" Since for each model both bars are formed by the same material only one `materials` struct is defined. The constitutive behavior considered in the first analysis case is an elastic behavior for the Rotated Engineering strain, then:","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"materials.modelName  = 'elastic-rotEngStr';","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":" and in the field `modelParams` a vector with the parameters of the Engineering Strain model is set","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"materials.modelParams = [E nu];","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":" which in the case of this material model are the Young modulus and the Poisson ratio.\n The field `density` is not set, then the default $\\rho = 0$ value is considered by ONSAS.\n\n#### elements\n The `elements` struct is initialized as empty","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"elements             = {};","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"Two different types of elements are required to create the model: `node` and `truss`, thus, the `elements` struct will have two entries. The type of the first entry is","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"elements(1).elemType = 'node';","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":" and the second entry is","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"elements(2).elemType = 'truss';","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":" for the geometries, the node has no geometry to assign, and the truss elements will be set as the native `circle` cross-section, then the elemCrossSecParams field is:","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"elements(2).elemCrossSecParams = { 'circle', sqrt(A * 4 / pi) };","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"\n#### boundaryConds\n\n The elements are submitted to two different BoundaryConditions, then the struct `boundaryConds` will have length two.\n The nodes $1$ and $3$ are fixed, without loads applied (this is the first BC), and node $2$ has a constraint in displacement and an applied load (second BC).\n For the displacements, the first BC corresponds to a xyz-fixed displacement,\n","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"boundaryConds                  = {}; boundaryConds(1).imposDispDofs = [1 3 5]; boundaryConds(1).imposDispVals = [0 0 0];","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"and the second BC corresponds to a zero displacement only in the $y$ direction.","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"boundaryConds(2).imposDispDofs =  3; boundaryConds(2).imposDispVals =  0;","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":" Regarding the loads, the second BC is set so that the final load factor is $3 \\cdot 10^8$ at 1 second. The default zero density is used, then no inertial effects are considered.\n","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"boundaryConds(2).loadsCoordSys = 'global'; boundaryConds(2).loadsTimeFact = @(t) 3.0e8 * t; boundaryConds(2).loadsBaseVals = [0 0 0 0 -1 0];","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"\n### mesh parameters\n\nThe coordinates of the nodes of the mesh are given by the matrix:","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"mesh             = {}; mesh.nodesCoords = [0  0   0; ...                     x2  0  z2; ...                     2 * x2  0   0];","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":" where the columns 1,2 and 3 correspond to $x$, $y$ and $z$ coordinates, respectively, and the row $i$-th corresponds to the coordinates of node $i$.\n\nThe connectivity is introduced using the _conecCell_ cell. Each entry of the cell (indexed using {}) contains a vector with the four indexes of the MEB parameters, followed by the indexes of the nodes of the element (node connectivity). For didactical purposes each element entry is commented. First the cell is initialized:","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"mesh.conecCell = cell(5, 1);","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":" Then the entry of node $1$ is introduced:","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"mesh.conecCell{ 1, 1 } = [0 1 1   1];","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":" the first MEB parameter (Material) is set as _zero_ (since nodes dont have material). The second parameter corresponds to the Element, and a _1_ is set since `node` is the first entry of the  `elements.elemType` cell. For the BC index, we consider that node $1$ is fixed, then the first index of the `boundaryConds` struct is used. Finally, at the end of the vector the number of the node is included (1).\n A similar approach is used for node $3$,","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"mesh.conecCell{ 2, 1 } = [0 1 1  3];","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":" and for node $2$ only the boundary condition is changed.","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"mesh.conecCell{ 3, 1 } = [0 1 2  2];","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":" Regarding the truss elements, the first material is considered, the second type of element, and no boundary conditions are applied.","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"mesh.conecCell{ 4, 1 } = [1 2 0   1 2]; mesh.conecCell{ 5, 1 } = [1 2 0   2 3];","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"\n#### initial Conditions\n homogeneous initial conditions are considered, then an empty cell is set:","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"initialConds = {};","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"\n### analysisSettings\n The method used in the analysis is the Newton-Raphson, then the field `methodName` must be introduced as:","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"analysisSettings               = {}; analysisSettings.methodName    = 'newtonRaphson';","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":" and the following parameters correspond to the iterative numerical analysis settings","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"analysisSettings.deltaT        =   0.1; analysisSettings.finalTime     =   1; analysisSettings.stopTolDeltau =   1e-9; analysisSettings.stopTolForces =   1e-9; analysisSettings.stopTolIts    =   15;","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"\n### otherParams","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"otherParams              = struct(); otherParams.problemName  = 'staticVonMisesTrussNRRotEng'; otherParams.plotsformat = 'vtk'; otherParams.plotsdeltaTs_separation = 2;","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"\n### Analysis case 1: Newton-Raphson with Rotated Eng Strain\n In the first case ONSAS is run and the solution at the dof of interest is stored.","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"[modelCurrSol, modelProperties, BCsData] = ONSAS_init(materials, elements, boundaryConds, initialConds, mesh, analysisSettings, otherParams); %","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"After that the structs are used to perform the numerical time analysis","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"[matUs, loadFactorsMat, solutions] = ONSAS_solve(modelCurrSol, modelProperties, BCsData);","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"controlDispsNREngRot =  -matUs(11, :); loadFactorsNREngRot  =  loadFactorsMat(:, 2);","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"\n### Analysis case 2: Newton-Raphson with linear elastic behavior\nIn this case a linear elastic behavior is assumed. Then the material modelName is overwritten","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"materials.modelName = 'elastic-linear'; otherParams.problemName  = 'staticVonMisesTruss_elastic-linear'; analysisSettings.finalTime  =   1.5;","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":" and the analysis is run again","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"[modelCurrSol, modelProperties, BCsData] = ONSAS_init(materials, elements, boundaryConds, initialConds, mesh, analysisSettings, otherParams); %","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"After that the structs are used to perform the numerical time analysis","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"[matUs, loadFactorsMat, solutions] = ONSAS_solve(modelCurrSol, modelProperties, BCsData);","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":" the displacements are extracted","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"controlDispsNRlinearElastic =  -matUs(11, :); loadFactorsNRlinearElastic  =  loadFactorsMat(:, 2);","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"\n and the analytic values of the load factor are computed, as well as its difference with the numerical solution\n","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"analyticLoadFactorsNREngRot = @(w) -2 * E * A * ...      (((z2 + (-w)).^2 + x2^2 - L^2) ./ (L * (L + sqrt((z2 + (-w)).^2 + x2^2)))) .* ...        (z2 + (-w))                    ./ (sqrt((z2 + (-w)).^2 + x2^2)); difLoadEngRot = analyticLoadFactorsNREngRot(controlDispsNREngRot)' - loadFactorsNREngRot;","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"\n### Analysis case 3: NR with Green Strain\n In order to perform a SVK case analysis, the material is changed and the problemName is also updated","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"elements(2).elemCrossSecParams = { 'generic', [A 1 1 1] }; otherParams.problemName  = 'staticVonMisesTrussNRGreen'; materials.modelName      = 'elastic-SVK'; analysisSettings.finalTime =   1.0; lambda = E * nu / ((1 + nu) * (1 - 2 * nu)); mu = E / (2 * (1 + nu)); materials.modelParams = [lambda mu];","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":" the load history is also changed","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"boundaryConds(2).loadsTimeFact = @(t) 1.5e8 * t; % boundaryConds(2).userLoadsFilename = 'myVMLoadFunc' ;","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":" and the analysis is run","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"[modelCurrSol, modelProperties, BCsData] = ONSAS_init(materials, elements, boundaryConds, initialConds, mesh, analysisSettings, otherParams); %","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"After that the structs are used to perform the numerical time analysis","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"[matUs, loadFactorsMat, solutions] = ONSAS_solve(modelCurrSol, modelProperties, BCsData);","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":" and the displacements are extracted","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"controlDispsNRGreen =  -matUs(11, :); loadFactorsNRGreen  =  loadFactorsMat(:, 2);","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":" the analytic solution is computed","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"analyticLoadFactorsGreen = @(w) -2 * E * A * ((z2 + (-w)) .* (2 * z2 * (-w) + w.^2)) ./ (2.0 * L^3); difLoadGreen = analyticLoadFactorsGreen(controlDispsNRGreen)' - loadFactorsNRGreen;","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"\n### Analysis case 4: NR-AL with Green Strain\n\nIn this case the rectangle section is considered (with the same area as the previous cases) and the Arc-Length resolution method is used.","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"otherParams.problemName       = 'staticVonMisesTrussNRALGreen';","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"the section is changed","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"elements(2).elemCrossSecParams{1, 1} = 'rectangle'; elements(2).elemCrossSecParams{2, 1} = [sqrt(A) sqrt(A)];","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":" the numerical method is changed","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"analysisSettings.methodName   = 'arcLength'; analysisSettings.finalTime    = 1;","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":" a varying step of displacements is considered","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"analysisSettings.incremArcLen = [0.15 * ones(1, 8) 0.3 * ones(1, 2)]; analysisSettings.iniDeltaLamb = boundaryConds(2).loadsTimeFact(.2) / 100; analysisSettings.posVariableLoadBC = 2;","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"[modelCurrSol, modelProperties, BCsData] = ONSAS_init(materials, elements, boundaryConds, initialConds, mesh, analysisSettings, otherParams); %","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"After that the structs are used to perform the numerical time analysis","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"[matUs, loadFactorsMat, solutions] = ONSAS_solve(modelCurrSol, modelProperties, BCsData);","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"controlDispsNRALGreen =  -matUs(11, :); loadFactorsNRALGreen  =  loadFactorsMat(:, 2); analyticLoadFactorsNRALGreen = analyticLoadFactorsGreen(controlDispsNRALGreen); difLoadGreenNRAL = analyticLoadFactorsNRALGreen' - loadFactorsNRALGreen;","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"\n### Analysis case 5: NR-AL Jirasek variant\n","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"elements(2).elemCrossSecParams = { 'rectangle', [sqrt(A) sqrt(A)] }; otherParams.problemName       = 'staticVonMisesTrussNRALJirasek_Green'; analysisSettings.incremArcLen = 0.15;","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":" Sets arcLengthFlag = 2 to secifiy Jirasek constraint method.","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"analysisSettings.ALdominantDOF = [11 -1];","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"[modelCurrSol, modelProperties, BCsData] = ONSAS_init(materials, elements, boundaryConds, initialConds, mesh, analysisSettings, otherParams); %","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"After that the structs are used to perform the numerical time analysis","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"[matUs, loadFactorsMat, solutions] = ONSAS_solve(modelCurrSol, modelProperties, BCsData);","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"controlDispsNRALJirasekGreen =  -matUs(11, :); loadFactorsNRALJirasekGreen  =  loadFactorsMat(:, 2); analyticLoadFactorsNRALJirasekGreen = analyticLoadFactorsGreen(controlDispsNRALJirasekGreen); difLoadGreenNRALJirasek = analyticLoadFactorsNRALJirasekGreen' - loadFactorsNRALJirasek_Green;","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"## Verification\n the numerical resolution is validated for both strain measures.\n","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"verifBoolean =  ((norm(difLoadEngRot) / norm(loadFactorsNREngRot)) <  1e-4) && ...                 ((norm(difLoadGreen) / norm(loadFactorsNRGreen)) <  1e-4) && ...                 ((norm(difLoadGreenNRAL) / norm(loadFactorsNRALGreen)) <  1e-4) && ...                 ((norm(difLoadGreenNRALJirasek) / norm(loadFactorsNRALJirasek_Green)) <  1e-4);","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"\n### Plots\n and solutions are plotted.","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"lw = 2.0; ms = 11; plotfontsize = 18; figure; plot(controlDispsNREngRot, analyticLoadFactorsNREngRot(controlDispsNREngRot), 'b-x', 'linewidth', lw, 'markersize', ms); hold on; grid on; plot(controlDispsNREngRot, loadFactorsNREngRot, 'k-o', 'linewidth', lw, 'markersize', ms); plot(controlDispsNRALGreen, analyticLoadFactorsGreen(controlDispsNRALGreen), 'g-x', 'linewidth', lw, 'markersize', ms); plot(controlDispsNRGreen, loadFactorsNRGreen, 'r-s', 'linewidth', lw, 'markersize', ms); plot(controlDispsNRALGreen, loadFactorsNRALGreen, 'c-^', 'linewidth', lw, 'markersize', ms); plot(controlDispsNRALJirasekGreen, loadFactorsNRALJirasekGreen, 'y-*', 'linewidth', lw, 'markersize', ms); plot(controlDispsNRlinearElastic, loadFactorsNRlinearElastic, 'm-+', 'linewidth', lw, 'markersize', ms); labx = xlabel('Displacement w(t)'); laby = ylabel('\\lambda(t)'); legend('analytic-RotEng', 'NR-RotEng', 'analytic-Green', 'NR-Green', 'NRAL-Green', 'NRAL-Jirasek-Green', 'elastic-linear', 'location', 'northoutside'); set(gca, 'linewidth', 1.0, 'fontsize', plotfontsize); set(labx, 'FontSize', plotfontsize); set(laby, 'FontSize', plotfontsize); print('output/vonMisesTrussCheck.png', '-dpng');","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"","category":"page"},{"location":"examples/staticVonMisesTruss/","page":"Static Von-Mises Truss","title":"Static Von-Mises Truss","text":"@raw html <img src=\"../../assets/generated/vonMisesTrussCheck.png\" alt=\"plot check\" width=\"500\"/> ```","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"% Copyright 2024, ONSAS Authors (see documentation) % % This file is part of ONSAS. % % ONSAS is free software: you can redistribute it and/or modify % it under the terms of the GNU General Public License as published by % the Free Software Foundation, either version 3 of the License, or % (at your option) any later version. % % ONSAS is distributed in the hope that it will be useful, % but WITHOUT ANY WARRANTY; without even the implied warranty of % MERCHANTABILITY or FITNESS FOR A PARTICULAR PURPOSE.  See the % GNU General Public License for more details. % % You should have received a copy of the GNU General Public License % along with ONSAS.  If not, see https://www.gnu.org/licenses/. %","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"# Reconfiguration cantilever beam example\n\n [![Octave script](https://img.shields.io/badge/script-url-blue)](https://github.com/ONSAS/ONSAS/blob/master/examples/dragBeamReconfiguration/dragBeamReconfiguration.m)\n\n In this tutorial, a cantilever beam submitted to a flow producing drag forces is considered. The main goal is to validate the drag forces computation considering reconfiguration in a problem with large displacements. The example is based on one of the problems considered in [this reference](https://www.cambridge.org/core/journals/journal-of-fluid-mechanics/article/drag-reduction-of-flexible-plates-by-reconfiguration/A3A066DE3886C40B1463508C92D1C81D), where a reference solution is presented and validated with experimental data. The reference solution was generated with the code publicly available in [this repository](https://github.com/lm2-poly/Reconfiguration-Beam/blob/master/reconfiguration.m)\n\n The problem consists in a cantilever beam submitted to a fluid flow with uniform velocity $v_a$($x$,$t$) = $v_a$(t) $c_2$, as shown int he Figure bellow. The beam is clamped on the boundary at $x=0$ m, and the span length is $L$. The cross-section of the beam is circular with diameter $d$. For the material of the beam a linear elastic isotropic model is considered, with Young modulus $E$ density $\\rho$.\n","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"@raw html <img src=\"../../assets/dragBeamReconfiguration/ilus.svg\" alt=\"general sketch\" width=\"450\"/>","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"## Dimensionless analysis\n--------------------\n\nThe problem can be studied through the following dimensionless numbers:\n","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"math  cy = \\frac{\\rhof L^3 va^2}{16 E I{zz}}, \\qquad \\mathcal{R} = \\frac{F}{\\frac{1}{2}\\rhof L d cd v_a^2}","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":" where  $F$ is the global drag force towards $c_2$, $c_y$ is the Cauchy number that describes the ratio between the stiffness of the beam and the flow load and the reconfiguration number $\\mathcal{R}$ reflects the geometric nonlinear effect by dividing the drag of the flexible beam to that of a rigid one of the same geometry\n## Numerical solution\n---------------------\n Before defining the structs, the workspace is cleaned and the ONSAS directory is added:","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"close all; if ~strcmp(getenv('TESTS_RUN'), 'yes')   clear all; end addpath(genpath([pwd '/../../src']));","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"\n The problem parameters are loaded:","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"[L, d, Izz, E, nu, rhoS, rhoF, nuF, ~, NR, cycdvec, uydotvec] = loadParametersCirc();","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":" where $\\rho_f$ and $\\rho_s$ are the fluid and solid densities respectively, $\\nu$ is the fluid kinematic viscosity, and  $NR$ is the number of load steps (or velocity cases solved):\n\n\n The number of elements employed to discretize the beam is:","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"numElements = 10;","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"\n### MEB parameters\n\n### materials\n Since the example contains only one material and co-rotational strain element so then `materials` struct is:","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"materials                 = struct(); materials.modelName  = 'elastic-rotEngStr'; materials.modelParams = [E nu]; materials.density         = rhoS;","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"\n### elements\n\n Two different types of elements are considered, node and frames. The nodes will be assigned in the first entry (index $1$) and the beam at the index $2$. The _elemType_ field is then:","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"elements(1).elemType = 'node'; elements(2).elemType = 'frame';","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":" for the geometries, the node has not geometry to assign (empty array), and frame elements will be set as a circular section with $d$ diameter.","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"elements(2).elemCrossSecParams{1, 1} = 'circle'; elements(2).elemCrossSecParams{2, 1} = [d];","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":" where the aerodynamic coefficents and the chord vector are set by default for `'circle'` cross sections type. For the validation case a constant drag coefficients $c_d =1.2\" is used, this is defined in the `'dragCircular'` function:","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"elements(2).aeroCoefFunctions = {'dragCircular', [], []};","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"\n### boundaryConds\n\n Only one welded (6 degrees of freedom are set to zero) boundary condition (BC) is considered:","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"boundaryConds = struct(); boundaryConds(1).imposDispDofs = [1 2 3 4 5 6]; boundaryConds(1).imposDispVals = [0 0 0 0 0 0];","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"\n### initial Conditions\n Any non-homogeneous initial condition (IC) are set for this case, then an empty struct is used:","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"initialConds = struct();","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"\n### mesh parameters\nThe coordinates of the mesh nodes are given by the matrix:","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"mesh = struct(); mesh.nodesCoords = [(0:(numElements))' * L / numElements  zeros(numElements + 1, 2)];","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"The connectivity is introduced using the _conecCell_. Each entry of the cell contains a vector with the four indexes of the MEB parameters, followed by the indexes of nodes that compose the element (node connectivity). For didactical purposes each element entry is commented. First the cell is initialized:","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"mesh.conecCell = { };","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":" then the first welded node is defined with material (M) zero since nodes don't have material, the first element (E) type (the first entry of the `elements` struct), and (B) is the first entry of the the `boundaryConds` struct. Finally the node is assigned:","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"mesh.conecCell{ 1, 1 } = [0 1 1   1];","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":" Next the frame elements MEB parameters are set. The frame material is the first material of `materials` struct, then $1$ is assigned. The second entry of the `elements` struct correspond to the frame element employed, so $2$ is set. Finally no BC is required for this element, then $0$ is used.  Consecutive nodes build the element so then the `mesh.conecCell` is:","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"for i = 1:numElements   mesh.conecCell{ i + 1, 1 } = [1 2 0   i i + 1]; end","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"\n### analysisSettings\n\n The fluid properties are set into _fluidProps_ field into `analysisSettings` struct. In this field the fluid velocity, viscosity and density are defined, This will apply a external fluid loads according to the quasi-steady theory for each element with aerodynamic coefficients fields into the `elements` struct. The name of the fluid velocity function located on the same example path is introduced as a string `'windVelCircStatic'`:","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"analysisSettings = struct(); analysisSettings.fluidProps = {rhoF; nuF; 'windVelCircStatic'};","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":" The geometrical non-linear effects and the aerodynamic stiffness matrix are considered in this case to compute the aerodynamic force vector:","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"analysisSettings.geometricNonLinearAero = true; analysisSettings.computeAeroStiffnessMatrix = true;","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":" since this problem is static, then a N-R method is employed. The time step `deltaT` is 1 since the time here is an index in the fluid velocity vector `uydot_vec` untile the length of this vector `NR` is reached:","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"analysisSettings.deltaT        =   1; analysisSettings.finalTime     =   NR; analysisSettings.methodName    = 'newtonRaphson';","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":" Next the maximum number of iterations per load(time) step, the residual force and the displacements tolerances are set to (if null tolerance is set the criterion is not considered):","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"analysisSettings.stopTolDeltau =   0; analysisSettings.stopTolForces =   1e-8; analysisSettings.stopTolIts    =   50;","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"\n### otherParams\n The name of the problem and vtk format output are selected:","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"otherParams  = struct(); otherParams.problemName = 'staticReconfigurationCircleUserDefinedDrag'; otherParams.plots_format = 'vtk';","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"\n### Case 1: validation case with constant $c_d = 1.2$\n\n The ONSAS software is executed for the parameters above defined and the displacement solution of each load(time) step is saved in `matUsCase1`matrix:\n\n The reaction forces at $x=0$ are stored  in the following vector and declaring a global variable:","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"global globalReactionForces globalReactionForces = zeros(6 * analysisSettings.finalTime, 1);","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"\n The node index where the reaction forces are computed is:","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"global glboalNodeReactionForces glboalNodeReactionForces = 1;","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"\n### Numeric solution\n\n Execute ONSAS and save the results:","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"[modelCurrSol, modelProperties, BCsData] = ONSAS_init(materials, elements, boundaryConds, initialConds, mesh, analysisSettings, otherParams); %","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"After that the structs are used to perform the numerical time analysis","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"[matUsCase1, loadFactorsMat, modelSolutions] = ONSAS_solve(modelCurrSol, modelProperties, BCsData);","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"\n## Verification\n---------------------\n The numerical solution is extracted. First the reference coordinaes","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"xref = mesh.nodesCoords(:, 1); yref = mesh.nodesCoords(:, 2); zref = mesh.nodesCoords(:, 3);","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":" Then the values of $R$ and $C_y C_d$ are computed :","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"numLoadSteps = size(matUsCase1, 2); timeVec = linspace(0, analysisSettings.finalTime, numLoadSteps); % initialize vectors Cy = zeros(numLoadSteps - 1, 1); R  = zeros(numLoadSteps - 1, 1); C_d = feval(elements(2).aeroCoefFunctions{1}, 0, 0); % fill them for windVelStep = 1:numLoadSteps - 1   % Compute dimensionless magnitudes   windVel         = feval(analysisSettings.fluidProps{3, :}, 0, timeVec(windVelStep + 1));   normWindVel     = norm(windVel);   dirWindVel      = windVel / normWindVel;   Cy(windVelStep) =  1 / 2 * rhoF * normWindVel^2 * (L)^3 * d / (E * Izz);","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"% numeric drag   FReaction = globalReactionForces((windVelStep - 1) * 6 + 1:windVelStep * 6);   FDragi = FReaction(3);   FDRef  = 1 / 2 * rhoF * normWindVel^2 * C_d * d * L;   R(windVelStep) =  abs(FDragi) / (FDRef);","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"end","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"\n### Gosselin et.Al 2010 solution\n","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"% resudrag (cycd, R) and def wich contains de deformed configuration for 10^i cycyd values: basedir = ''; if strcmp(getenv('TESTSRUN'), 'yes') && isfolder('examples')   basedir = ['.' filesep 'examples' filesep 'dragBeamReconfiguration' filesep]; end load([basedir 'Gosselin2010_data.mat'], 'def', 'resudrag');","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"\n### Validation plots\n\n The plot parameters are:","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"lw = 4; ms = 8; axislw = 1; axisFontSize = 20; legendFontSize = 15; curveFontSize = 15; Gline = 'k-'; ONSASline = 'bo'; ONSASlineBuiltInDrag = 'rx'; folderPathFigs = './output/figs/'; mkdir(folderPathFigs);","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"\n The modified Cauchy number vs R is plotted:\n","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"fig1 = figure(1); loglog(Cd * Cy, R, ONSASline, 'linewidth', lw, 'markersize', ms); hold on; loglog(resudrag(:, 1), resudrag(:, 2), Gline, 'linewidth', lw, 'markersize', ms); % add legend legend('ONSAS', 'Gosselin2010'); % set labels legend labx = xlabel(' cy*cd '); laby = ylabel('R'); set(legend, 'linewidth', axislw, 'fontsize', legendFontSize, 'location', 'eastOutside'); % set fonts set(gca, 'linewidth', axislw, 'fontsize', curveFontSize); set(labx, 'FontSize', axisFontSize); set(laby, 'FontSize', axisFontSize); grid on; if length(getenv('TESTSRUN')) > 0 && strcmp(getenv('TESTS_RUN'), 'yes')   fprintf('\\ngenerating output png for docs.\\n');   figure(1);   print('output/RvsCyCd.png', '-dpng'); else   fprintf('\\n === NOT in docs workflow. ===\\n'); end","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"\n Deformed configurations for different cauchy numbers\n","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"fig3 = figure(3); % plot reference configuration plot(xref, yref, 'k–', 'linewidth', lw, 'markersize', ms); hold on; grid on; % add markers for the legend plot(0, 0,  ONSASline, 'linewidth', lw, 'markersize', ms); plot(0, 0,  ONSASlineBuiltInDrag, 'linewidth', lw, 'markersize', ms); % plot deformed configurations for different fluid load steps for nr = 1:analysisSettings.finalTime   % Numerical deformed coordinates solution   xdef = xref + matUsCase1(1:6:end, nr + 1);   ydef = yref + matUsCase1(3:6:end, nr + 1);   zdef = zref + matUsCase1(5:6:end, nr + 1);   thetaXdef = matUsCase1(2:6:end, nr + 1);   thetaYdef = matUsCase1(4:6:end, nr + 1);   thetaZdef = matUsCase1(6:6:end, nr + 1);   % Gosselin deformed coordinates solution   xdefG = def(1, :, nr);   ydefG = -def(2, :, nr);   % Plot   plot(xdef,  ydef,  ONSASline, 'linewidth', lw, 'markersize', ms);   plot(xdefG, ydefG,  Gline, 'linewidth', lw, 'markersize', ms); end","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"\n### Verification boolean\n","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"% The verification boolean is computed as for the deformed configurations and the cycd curve % deformed coordinates dif norm vecDifDeform =  [norm(ydef - ydefG(1:numElements * 10:end)'); ...                  norm(xdef - xdefG(1:numElements * 10:end)')];","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"% verification boolean deformed verifBooleanDef =  vecDifDeform <=  2e-2 * L; % cycd vs R verification boolean is: verifBooleanR = abs(R(end) - resudrag(end, 2)) <  5e-3; % The example verifboolean is: verifBoolean = verifBooleanR && all(verifBooleanDef);","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"@raw html <img src=\"../../assets/generated/RvsCyCd.png\" alt=\"plot check deformed configurations\" width=\"500\"/>","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"\n### Case 2: case with drag coefficient formula proposed in [this reference](https://ascelibrary.org/doi/10.1061/%28ASCE%29HY.1943-7900.0000722)\n\n  Once `_elemCrossSecParams_` is defined in the `elements` struct then the drag lift and pitch moment are defined with bluit-in functions. As consequence if we want to use the default drag coefficient the `dragCoefFunction` field must be set:","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"elements(2).aeroCoefFunctions = {[], [], []};","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":" moreover the drag formulation in [this reference](https://ascelibrary.org/doi/10.1061/%28ASCE%29HY.1943-7900.0000722) is valid with $Re < 2$ x $10^5$. Then the final load step, which is equivalent to the index in the velocity vector `uydot_vec`, is set to 5:","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"analysisSettings.finalTime = NR - 2;","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"\n### otherParams\n The name of the problem and vtk format output are selected:","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"otherParams  = struct(); otherParams.problemName = 'staticReconfigurationCircleBuiltInDrag';","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"\n### Numeric solution\n","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"[modelCurrSol, modelProperties, BCsData] = ONSAS_init(materials, elements, boundaryConds, initialConds, mesh, analysisSettings, otherParams); %","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"After that the structs are used to perform the numerical time analysis","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"[matUsCase2, loadFactorsMat, modelSolutions] = ONSAS_solve(modelCurrSol, modelProperties, BCsData);","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"\n the report is generated","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"outputReport(modelProperties.outputDir, modelProperties.problemName);","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"\n Deformed configurations for different cauchy numbers\n","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"for nr = 1:analysisSettings.finalTime   % Numerical deformed coordinates solution   xdefCase2 = xref + matUsCase2(1:6:end, nr + 1);   ydefCase2 = yref + matUsCase2(3:6:end, nr + 1);   zdefCase2 = zref + matUsCase2(5:6:end, nr + 1);   thetaXdefCase2 = matUsCase2(2:6:end, nr + 1);   thetaYdefCase2 = matUsCase2(4:6:end, nr + 1);   thetaZdefCase2 = matUsCase2(6:6:end, nr + 1);   % Plot   plot(xdefCase2,  ydefCase2,  ONSASlineBuiltInDrag, 'linewidth', lw, 'markersize', ms); end % add legend legend('Gosselin2010(cd = 1.2)', 'ONSAS(cd = 1.2)', 'ONSAS(Built-in cd)'); % add legends and labels labx = xlabel('x [m]'); laby = ylabel('y [m]'); % set fonts set(legend, 'linewidth', axislw, 'fontsize', legendFontSize, 'location', 'eastOutside'); set(gca, 'linewidth', axislw, 'fontsize', curveFontSize); set(labx, 'FontSize', axisFontSize); set(laby, 'FontSize', axisFontSize); % axis equal % save fig namefig3 = strcat(folderPathFigs, 'xy.png'); if length(getenv('TESTSRUN')) > 0 && strcmp(getenv('TESTS_RUN'), 'yes')   fprintf('\\ngenerating output png for docs.\\n');   figure(3);   print('output/defPlots.png', '-dpng'); else   fprintf('\\n === NOT in docs workflow. ===\\n'); end","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"","category":"page"},{"location":"examples/dragBeamReconfiguration/","page":"Reconfiguration beam","title":"Reconfiguration beam","text":"@raw html <img src=\"../../assets/generated/defPlots.png\" alt=\"plot check deformed configurations\" width=\"500\"/> ```","category":"page"},{"location":"creatingModels/#Creating-structural-models","page":"Creating Models","title":"Creating structural models","text":"","category":"section"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"The data and properties of each structural model are defined through a set of definitions in a .m script. These properties are stored in struct data structures. The following structs must be defined and provided as input to the ONSAS function in this order:","category":"page"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"materials\nelements\nboundaryConds\ninitialConds\nmesh\nnumericalMethod\notherParams","category":"page"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"Each struct has its own fields with specific names, used to store each corresponding property or information. Each field is obtained or assigned using structName.fieldName. A description of each struct and its fields follows at next. It is highly recommended to read the current sectiong following one of the examples presented in the documentation. ","category":"page"},{"location":"creatingModels/#materials","page":"Creating Models","title":"materials","text":"","category":"section"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"The materials vector of structs contains at each entry i the information of the i-th material used in the mesh.conecCell for each element.","category":"page"},{"location":"creatingModels/#materials(i).modelName","page":"Creating Models","title":"materials(i).modelName","text":"","category":"section"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"This is field contains a string of the material model used to compute the internal forces of the structure. The models implemented in ONSAS are:","category":"page"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"'elastic-linear': used for linear behavior with small strains and small displacements. The scalar parameters of this model are p_1=E the Young modulus and p_2=nu the Poisson's ratio.\n'elastic-SVK': used for a Saint-Venant-Kirchhoff material where the parameters p_1 and p_2 are the Lamé parameters with the strain-energy density function given by the following equation (where textbfE is the Green-Lagrange strain tensor)","category":"page"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"Psi( textbfE ) = fracp_12 tr(textbfE)^2 + p_2 tr(textbfE^2)\nquad\np_1 = frac E nu  (1+nu) (1-2nu) \nquad\np_2 = frac E  2 (1+nu) ","category":"page"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"'elastic-NHC': used for a Neo-Hookean compressible material. The model implemented is given by","category":"page"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"Psi( textbfC ) = fracp_12 ( tr(textbfC)-3 -2 L( sqrtdet(textbfC) ) ) + fracp_22 left( sqrtdet(textbfC)-1 right)^2\n quad\n p_1 = frac E  2 (1+nu) \n quad\n p_2 = frac E  3 (1-2 nu) ","category":"page"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"'elastic-rotEngStr': used for 1D elements (truss or frame) under large displacements.\n'elastic-rotLogStr': used for 1D elements (truss) under large displacements.\n'plastic': an ElastoPlastic material with isotropic hardening given by the von mises flow rule for the plane strain element. The parameters are introduced as: p_1=E , p_2 = K and p_3=sigma_Y0.\n'plastic-rotEngStr': an ElastoPlastic material .\n'plastic-rotLogStr': an ElastoPlastic material .","category":"page"},{"location":"creatingModels/#materials(i).modelParams","page":"Creating Models","title":"materials(i).modelParams","text":"","category":"section"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"A vector with the properties of this material model.","category":"page"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":" p_1 dots p_n_P ","category":"page"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"where n_P is the number of parameters of the constitutive model and mathbfp is the vector of constitutive parameters.","category":"page"},{"location":"creatingModels/#materials(i).density","page":"Creating Models","title":"materials(i).density","text":"","category":"section"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"This is the scalar value of the density of the material.","category":"page"},{"location":"creatingModels/#materials(i).nodalMass","page":"Creating Models","title":"materials(i).nodalMass","text":"","category":"section"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"This fields sets a vector of nodal masses components m_x m_y m_z that is assigned to nodes.","category":"page"},{"location":"creatingModels/#elements","page":"Creating Models","title":"elements","text":"","category":"section"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"The elements vector of structs contains at each entry i the information of the i-th finite element type used in the mesh.conecCell for each element of the mesh.","category":"page"},{"location":"creatingModels/#elements(i).elemType","page":"Creating Models","title":"elements(i).elemType","text":"","category":"section"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"A string representing the type of element. The possible strings are: node, truss, frame, edge, triangle or tetrahedron.","category":"page"},{"location":"creatingModels/#elements(i).elemTypeParams","page":"Creating Models","title":"elements(i).elemTypeParams","text":"","category":"section"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"A scalar or vector with auxiliary parameters, required for some element types:","category":"page"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"triangle vector with parameters, the first parameter is an integer indicating if plane stress (1) or plane strain (2) case is considered.","category":"page"},{"location":"creatingModels/#elements(i).massMatType","page":"Creating Models","title":"elements(i).massMatType","text":"","category":"section"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"The massMatType field sets, for frame or truss elements, whether consistent or lumped mass matrix is used for the inertial term in dynamic analyses. The massMatType field should be set as a string variable: 'consistent' or 'lumped',  and if it is not declared then by default the 'lumped' mass matrix is set.","category":"page"},{"location":"creatingModels/#elements(i).elemCrossSecParams","page":"Creating Models","title":"elements(i).elemCrossSecParams","text":"","category":"section"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"This is a cell structure with the information of the geometry of the element.","category":"page"},{"location":"creatingModels/#1D-elements","page":"Creating Models","title":"1D elements","text":"","category":"section"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"For truss or frame elements, this cell has two entries, first a string with a name of the type of cross section, and in the second entry a vector of real parameters setting the shape of that section:","category":"page"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":" crossSectionTypeString   crossSectionParam_1 dots crossSectionParam_n  ","category":"page"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"with n being the number of parameters of the cross section type, and crossSectionTypeString the type of cross section. The possible cross section strings and their corresponding properties are:","category":"page"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"generic  :general sections, where areas and inertias are provided as parameters according to the vector: A  J  I_yy  I_zz  I_rho(11)  I_rho(22)  I_rho(33)   where A is the area, I_ii is the second moment of inertia of the cross-section respect to i direction, J is the polar moment of inertia and I_rho is the inertia tensor.\nrectangle: rectangular sections where thicknesses t_y and t_z are provided as the vector t_y t_z\ncircle : circular sections where diameter is provided.\npipe : circular hollow section where external and internal diameters are provided as first and second entries of the vector of elementCrossSecParams.","category":"page"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"For edge elements the thickness is expected (for 2D load computations).","category":"page"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"See the crossSectionProps.m function for more details.","category":"page"},{"location":"creatingModels/#2D-elements","page":"Creating Models","title":"2D elements","text":"","category":"section"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"For 2D elements such as triangle in this field a float number representing the thickness of the element is set.   ","category":"page"},{"location":"creatingModels/#elements(i).aeroCoefFunctions","page":"Creating Models","title":"elements(i).aeroCoefFunctions","text":"","category":"section"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"If a frame aerodynamic analysis is desired, the drag, lift and pitch moment functions should be defined using this field. This field should contain a cell with either the strings of the functions or the definition of anonymous functions for draf lif and pitch moment in that order. Each function must receive as first input the incidence angle and as second the Reynolds number. For some elemCrossSecParams like 'circle' internal built-in functions are set as default thus there is no need to set this field.","category":"page"},{"location":"creatingModels/#elements(i).chordVector","page":"Creating Models","title":"elements(i).chordVector","text":"","category":"section"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"A vector with the three coordinates of the aerodynamic chord vector (the system of coordinates considered for this is the local reference system at the undeformed configuration)","category":"page"},{"location":"creatingModels/#boundaryConds","page":"Creating Models","title":"boundaryConds","text":"","category":"section"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"The boundary condtion vector of structs contains at each entry i the information of the i-th boundary condtion used in the mesh.conecCell for each element.","category":"page"},{"location":"creatingModels/#boundaryConds(i).loadsCoordSys","page":"Creating Models","title":"boundaryConds(i).loadsCoordSys","text":"","category":"section"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"cell containing the coordinates system for the loads applied in each BC, each entry should be a 'global' string or a 'local', or an empty array if no load is applied in that BC setting [].","category":"page"},{"location":"creatingModels/#boundaryConds(i).loadsTimeFact","page":"Creating Models","title":"boundaryConds(i).loadsTimeFact","text":"","category":"section"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"cell with the inline function definitions of load factors of the loads applied of an empty array.","category":"page"},{"location":"creatingModels/#boundaryConds(i).loadsBaseVals","page":"Creating Models","title":"boundaryConds(i).loadsBaseVals","text":"","category":"section"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"cell with the (row) vector of the components of the load case","category":"page"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":" f_x   m_x  f_y  m_y  f_z  m_z ","category":"page"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"where f_i are the components of forces and m_i are the moments. Both forces or moments are considered per unit of length in the case of truss/frame/edge elements, or per unit of area in the case of triangle.","category":"page"},{"location":"creatingModels/#boundaryConds(i).userLoadsFileName","page":"Creating Models","title":"boundaryConds(i).userLoadsFileName","text":"","category":"section"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"string with the filename of the .m function file provided by the user that can be used to apply forces not given by time-varying loadFactors. This function file should be placed in the example folder and it must receive two arguments:  t (the time) and UsCell (a cell with: {the current displacement, velocity and acceleration} ). The function should one forces vector with the size of all the degrees of freedom of the problem (in global coordinates).","category":"page"},{"location":"creatingModels/#boundaryConds(i).imposDispDofs","page":"Creating Models","title":"boundaryConds(i).imposDispDofs","text":"","category":"section"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"vector with the local degrees of freedom imposed (integers from 1 to 6)","category":"page"},{"location":"creatingModels/#boundaryConds(i).imposDispVals","page":"Creating Models","title":"boundaryConds(i).imposDispVals","text":"","category":"section"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"vector with the values of the imposed displacements at the corresponding imposDispDofs.","category":"page"},{"location":"creatingModels/#boundaryConds(i).springDofs","page":"Creating Models","title":"boundaryConds(i).springDofs","text":"","category":"section"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"vector with the local degrees of freedom of the node with springs (integers from 1 to 6)","category":"page"},{"location":"creatingModels/#boundaryConds(i).springVals","page":"Creating Models","title":"boundaryConds(i).springVals","text":"","category":"section"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"vector with the values of the springs stiffnesses.","category":"page"},{"location":"creatingModels/#The-mesh-struct","page":"Creating Models","title":"The mesh struct","text":"","category":"section"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"The mesh struct contains the finite element mesh information.","category":"page"},{"location":"creatingModels/#mesh.nodesCoords","page":"Creating Models","title":"mesh.nodesCoords","text":"","category":"section"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"matrix with the coordinates of all the nodes of the mesh. The i-th row contains the three coordinates of the node i: x_i   y_i  z_i,","category":"page"},{"location":"creatingModels/#mesh.conecCell","page":"Creating Models","title":"mesh.conecCell","text":"","category":"section"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"cell array with the elements and node-connectivity information. The i1 entry contains the vector with the MEB (Material, Element, boundaryConds) indexes and the nodes of the i-th element. The structure of the vector at each entry of the cell is:","category":"page"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"  materialInd  elementInd  boundaryCondInd  node_1 dots node_n ","category":"page"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"where the first three indexes are natural numbers and n is the number of nodes required by the type of element. If no property is assigned the 0 index can be used, for instance, nodes used to introduced loads should be defined with materialIndex = 0.","category":"page"},{"location":"creatingModels/#The-initialConds-struct","page":"Creating Models","title":"The initialConds struct","text":"","category":"section"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"If initial conditions are homogeneous, then an empty struct should be defined using initialConds = struct() ;. Otherwise the fields that can be set are:","category":"page"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"initialConds.U: a vector of the displacements at time 0.\ninitialConds.Udot: a vector of the velocities  at time 0.\ninitialConds.Udotdot: a vector of the accelerations at time 0.","category":"page"},{"location":"creatingModels/#The-analysisSettings-struct","page":"Creating Models","title":"The analysisSettings struct","text":"","category":"section"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"This struct contains the parameters required to apply the numerical method for the resolution of the nonlinear equations:","category":"page"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"methodName: string with the name of the method used: 'newtonRaphson','arcLength', 'newmark','alphaHHT'.\nstopTolDeltau: float with tolerance for convergence in relative norm of displacements increment\nstopTolForces: float with tolerance for convergence in relative norm of residual loads\nstopTolIts: integer with maximum number of iterations per time step\ndeltaT: time step\nfinalTime: final time of simulation\nincremArcLen: radius of the cylinder for the arcLength method. if scalar is provided then this is fixed during all times. if a vector is provided then for each time t_i the entry i of the vector will be used as radius. Default is 015. \nALdominantDOF: if this is not set or set as [] (zero) then the cylindical ArcLength method based on DeSouzaNeto's Computational Methods for plasticity is used, if a non-empty vector is provided, then the dominant dof arc length variant based on Jirásek & Bazant, Inelastic Analysis of Structures, 2002, Chapter 22, is used, the first entry is the dof and the second the scaling factor\ndeltaNM: delta parameter of newmark method. If this parameter is not declared then the classic Trapezoidal Newmark delta = 12 is set.\nalphaNM: alpha parameter of newmark method. If this parameter is not declared then the classic  Trapezoidal Newmark alpha = 14 is set.\nalphaHHT: alpha parameter of alpha-HHT method. If this parameter is not declared then alpha=-005 is set.\nposVariableLoadBC: (parameter used by the arcLength method) this parameter is an integer with the entry of the boundaryConds cell corresponding with the loads vector affected by the load factor. Default is [].\niniDeltaLamb: (parameter used by the arcLength method) this parameter sets the initial increment for the load factor lambda. Default is 1e-3.","category":"page"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"another additional optional parameters are:","category":"page"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"booleanSelfWeight: a boolean indicating if self weight loads are considered or not. The loads are computed using the density of the material and in the -z global direction.\niniMatUs: a matrix with initial solutions for each time step.\naddedMassBoolean: if this parameter is set 'true' the fluid density is considered in the intertial forces term for frame elements.","category":"page"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"the aerodynamic-frame element parameters set are","category":"page"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"fluidProps: is a row cell with the density rho_f, viscosity nu_f and the function with the fluid velocity  ","category":"page"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":" rho_f  nu_f  fluidVelocity","category":"page"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"geometricNonLinearAero: a boolean parameter. If it is set as true geometric nonlinearity (or reconfiguration) is considered in the computation of the aerodynamic forces vector of all frame elements of the model.\nnumGaussPointsAeroForce:  number of Gauss integration points per element for the aerodynamic forces vector. Default is 4. \ncomputeAeroStiffnessMatrix: a boolean to compute the aerodynamic forces stiffness matrix using a central difference algorithm. Default is 'false', since can affect performance.  ","category":"page"},{"location":"creatingModels/#The-otherParams-struct","page":"Creating Models","title":"The otherParams struct","text":"","category":"section"},{"location":"creatingModels/","page":"Creating Models","title":"Creating Models","text":"problemName: string with the name of the problem, to be used in outputs.\nplots_format: string indicating the format of the output. Use 'vtk' for vtk output. default: no output.\nplots_deltaTs_separation: integer number N such that the time between vtk plots is N x deltaT.\ncontrolDofs: matrix with information of the degrees of freedom to compute and control. Each row should contain this form: [ node localdof ].\nstoreBoolean: boolean to store the results of the current iteration such as the displacements, tangent matrices, normal forces and stresses. [default: 1]\nnodalDispDamping: scalar value of a linear viscous damping factor applied for all the displacement degrees of freedom [default: 0]","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"% Copyright 2024, ONSAS Authors (see documentation) % % This file is part of ONSAS. % % ONSAS is free software: you can redistribute it and/or modify % it under the terms of the GNU General Public License as published by % the Free Software Foundation, either version 3 of the License, or % (at your option) any later version. % % ONSAS is distributed in the hope that it will be useful, % but WITHOUT ANY WARRANTY; without even the implied warranty of % MERCHANTABILITY or FITNESS FOR A PARTICULAR PURPOSE.  See the % GNU General Public License for more details. % % You should have received a copy of the GNU General Public License % along with ONSAS.  If not, see https://www.gnu.org/licenses/. %","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"# Uniaxial Compression example\n\n[![Octave script](https://img.shields.io/badge/script-url-blue)](https://github.com/ONSAS/ONSAS/blob/master/examples/uniaxialCompression/uniaxialCompression.m)\n\nIn this tutorial example an hyperelastic solid is submitted to a uniaxial compression test. The geometry and tension applied are shown in the figure, where the $Lx$, $Ly$ and $Lz$ are the dimensions. A nominal compression tension $p$ is applied on the face $x=Lx$, as a nominal tension. Non-friction contact boundary conditions are considered on faces $x=0$, $y=0$ and $z=0$.\n","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"@raw html <img src=\"../../assets/uniaxialCompression/diagramSolidUniaxialCompression.svg\" alt=\"structure diagram\" width=\"500\"/>","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"\n\n ## Analytic solution\n\nLet us consider that a uniform deformation is produced, with a nonzero axial stretch $\\alpha$ and nonzero transversal stretch $\\beta$. The corresponding deformation gradient and Green-Lagrange strain tensors are given by:\n","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"math \\textbf{F} = \\left[ \\begin{matrix} \\alpha & 0 & 0 \\ 0 & \\beta & 0 \\ 0 & 0 & \\beta \\end{matrix} \\right] \\qquad \\textbf{E} = \\frac{1}{2}(\\textbf{C} - \\textbf{I}) = \\left[  \\begin{matrix} \\frac{1}{2} \\left(\\alpha^2 -1\\right) & 0 & 0 \\ 0 &  \\frac{1}{2} \\left(\\beta^2 -1\\right) & 0 \\ 0 & 0 &  \\frac{1}{2} \\left(\\beta^2 -1\\right) \\end{matrix} \\right]","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":" where $\\alpha = (1+u_x/L_x)$ and $\\beta = (1+u_y/L_y)$, with $u_x$ and $u_y$ the linear displacements at $X=(L_x,L_y,L_z=L_y)$.\n\nThe neo-Hookean elastic strain energy potential $\\Psi$ is given by:","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"math \\Psi(\\mathbf{C=\\textbf{F}^T\\textbf{F}}) = \\frac{\\mu}{2}(I_1 -2ln(J)) + \\frac{K}{2} ( J -1 )^2","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"where $I_1 = \\mathrm{tr}(\\mathbf{C})$ is the first invariant, $J = \\sqrt{\\det(\\mathbf{C})}$ and $K$ and $\\mu$ are the bulk and shear material parameters, respectively.\n\nThe second Piola-Kirchhoff tensor is given by:","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"math \\textbf{S}( \\mathbf{C} ) = \\mu (\\textbf{I} - \\mathbf{C}^{-1}) + K (J(J-1)\\mathbf{C}^{-1})","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"then, on the one hand, using the relation $\\textbf{P}=\\textbf{F}\\textbf{S}$, the $P_{xx}$ nominal stress component is obtained and equaled to the applied compression:","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"math P_{xx}( \\mu,K ) =  \\alpha \\left(     \\mu -  \\frac{\\mu}{\\alpha^2} + \\frac{K\\beta^2}{\\alpha} (\\beta^2 \\alpha -1)  \\right) = - p","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":" and on the other hand, the $P_{yy}$ and $P_{zz}$ components are obtained and equaled to zero:","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"math P_{yy}( \\mu,K ) =  \\beta \\left(     \\mu -  \\frac{\\mu}{\\beta^2} + K (\\alpha^2\\beta^2 - \\alpha)  \\right) = 0","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"\n## Numerical solution\nBefore defining the structs, the workspace is cleaned, the ONSAS directory is added to the path and scalar geometry and material parameters are defined.","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"close all; if ~strcmp(getenv('TESTS_RUN'), 'yes')   clear all; end % add path addpath(genpath([pwd '/../../src'])); % scalar parameters E = 1; nu = 0.3; p = -5; Lx = 2; Ly = 1; Lz = 1;","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"\n\n### MEB parameters\n\n#### materials\n The material of the solid considered is a neo-Hookean model with $\\lambda$, $\\mu$ and bulk($K$) parameters:","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"lambda = E * nu / ((1 + nu) * (1 - 2 * nu)); mu = E / (2 * (1 + nu)); bulk = E / (3 * (1 - 2 * nu));","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":" since only one material is considered, a scalar struct is defined as follows","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"materials                 = struct(); materials.modelName  = 'NHC'; materials.modelParams = [mu bulk];","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"\n#### elements\n In this model two kinds of elements are used: `tetrahedron` for the solid and `triangle` for introducing the external loads. Since two kinds of elements are used, the struct have length 2:","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"elements             = struct(); elements(1).elemType = 'triangle'; elements(2).elemType = 'tetrahedron'; elements(2).elemTypeParams = [2];","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"\n#### boundaryConds\n in this case four BCs are considered, one corresponding to a load and three to displacements.\n the first BC introduced is a load, then the coordinate system, loadfactor time function and base load vector are defined","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"boundaryConds                  = struct(); boundaryConds(1).loadsCoordSys = 'global'; boundaryConds(1).loadsTimeFact = @(t) p * t; boundaryConds(1).loadsBaseVals = [1 0 0 0 0 0];","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":" the other BCs have imposed displacements","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"boundaryConds(2).imposDispDofs = [1]; boundaryConds(2).imposDispVals =  0; % boundaryConds(3).imposDispDofs = [3]; boundaryConds(3).imposDispVals =  0; % boundaryConds(4).imposDispDofs = [5]; boundaryConds(4).imposDispVals =  0;","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"\n\n### Mesh\n A simple hand-made 8-node mesh, with 6 tetrahedrons is considered\n","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"@raw html <img src=\"https://raw.githubusercontent.com/ONSAS/ONSAS_docs/master/docs/src/solidCubeMeshHTML.svg\" alt=\"mesh diagram\" width=\"500\"/>","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"@raw latex \\begin{center} \\def\\svgwidth{0.6\\textwidth} \\input{solidCubeMeshPDF.pdf_tex} \\end{center}","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":" The node coordinates matrix is given by","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"mesh             = struct(); mesh.nodesCoords = [0    0    0; ...                     0    0   Lz; ...                     0   Ly   Lz; ...                     0   Ly    0; ...                     Lx   0    0; ...                     Lx   0   Lz; ...                     Lx  Ly   Lz; ...                     Lx  Ly    0];","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":" and the connectivity cell is defined as follows with the four MEB parameters for each element followed by the indexes of the nodes of each element. All the eight triangle elements are considered with no material (since they are used only to include load) and the following six elements are solid neo-Hookean material tetrahedrons.","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"mesh.conecCell = {[0 1 1     5 8 6]; ... % loaded face                   [0 1 1     6 8 7]; ... % loaded face                   [0 1 2     4 1 2]; ... % x=0 supp face                   [0 1 2     4 2 3]; ... % x=0 supp face                   [0 1 3     6 2 1]; ... % y=0 supp face                   [0 1 3     6 1 5]; ... % y=0 supp face                   [0 1 4     1 4 5]; ... % z=0 supp face                   [0 1 4     4 8 5]; ... % z=0 supp face                   [1 2 0     1 4 2 6]; ... % tetrahedron                   [1 2 0     6 2 3 4]; ... % tetrahedron                   [1 2 0     4 3 6 7]; ... % tetrahedron                   [1 2 0     4 1 5 6]; ... % tetrahedron                   [1 2 0     4 6 5 8]; ... % tetrahedron                   [1 2 0     4 7 6 8]  ... % tetrahedron                  };","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"\n#### initialConds\n since no initial non-homogeneous initial conditions are used, an empty struct is used .","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"initialConds = struct();","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"\n### Analysis parameters\n","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"analysisSettings               = struct(); analysisSettings.methodName    = 'newtonRaphson'; analysisSettings.stopTolIts    = 30; analysisSettings.stopTolDeltau = 1.0e-8; analysisSettings.stopTolForces = 1.0e-8; analysisSettings.finalTime     = 1; analysisSettings.deltaT        = .1;","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"\n### Output parameters","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"otherParams             = struct(); otherParams.problemName = 'uniaxialCompressionHandMadeMesh'; otherParams.plotsformat = 'vtk';","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"[modelCurrSol, modelProperties, BCsData] = ONSAS_init(materials, elements, boundaryConds, initialConds, mesh, analysisSettings, otherParams); %","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"After that the structs are used to perform the numerical time analysis","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"[matUs, loadFactorsMat, modelSolutions] = ONSAS_solve(modelCurrSol, modelProperties, BCsData);","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"\n The displacement in $x$ of node 7 is computed:\n","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"controlDispsValsCase1 = matUs(6 * 6 + 1, :); loadFactorsCase1 = loadFactorsMat;","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"\n\n### Analytic solution computation\n\n The numerical values of $\\beta$ and $\\alpha$ for each load step are:","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"alphas       = (Lx + matUs(6 * 6 + 1, :)) / Lx; betas        = (Ly + matUs(6 * 6 + 3, :)) / Ly;","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":" and the corresponding analytic nominal tension is obtained","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"analyticFuncPxx = @(alphas, betas) mu * alphas - mu * 1 ./ alphas + bulk * betas.^2 .* (alphas .* betas.^2 - 1); analyticFuncPyy = @(alphas, betas) betas .* mu  - mu * 1 ./ betas + bulk * betas .* (alphas.^2 .* betas.^2 - alphas); analyticPxx = analyticFuncPxx(alphas, betas); analyticPyy = analyticFuncPyy(alphas, betas);","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"The error and the verif boolean are computed","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"aux1 = loadFactorsCase1' - analyticPxx; tolerance = 1e-6; verifBoolean = (norm(aux1) / norm(analyticPxx) < 1e-6) && (norm(analyticPyy) < tolerance);","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"\n## Plot\nThe numerical and analytic solutions are plotted.","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"lw = 2.0; ms = 11; plotfontsize = 18; figure; hold on; grid on; plot(controlDispsValsCase1, loadFactorsCase1, 'r-x', 'linewidth', lw, 'markersize', ms); plot(controlDispsValsCase1, analyticPxx,  'g-s', 'linewidth', lw, 'markersize', ms); labx = xlabel('Displacement'); laby = ylabel('\\lambda(t)'); legend('Numeric', 'Analytic', 'location', 'SouthEast'); set(gca, 'linewidth', 1.0, 'fontsize', plotfontsize); set(labx, 'FontSize', plotfontsize); set(laby, 'FontSize', plotfontsize); title('uniaxial compression test'); if length(getenv('TESTSRUN')) > 0 && strcmp(getenv('TESTSRUN'), 'yes')   fprintf('\\ngenerating output png for docs.\\n');   print('./output/verifCompression.png', '-dpng'); else   fprintf('\\n === NOT in docs workflow. ===\\n'); end","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"","category":"page"},{"location":"examples/uniaxialCompression/","page":"Uniaxial compression","title":"Uniaxial compression","text":"@raw html <img src=\"../../assets/generated/verifCompression.png\" alt=\"validation plot\" width=\"500\"/> ```","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"% Copyright 2024, ONSAS Authors (see documentation) % % This file is part of ONSAS. % % ONSAS is free software: you can redistribute it and/or modify % it under the terms of the GNU General Public License as published by % the Free Software Foundation, either version 3 of the License, or % (at your option) any later version. % % ONSAS is distributed in the hope that it will be useful, % but WITHOUT ANY WARRANTY; without even the implied warranty of % MERCHANTABILITY or FITNESS FOR A PARTICULAR PURPOSE.  See the % GNU General Public License for more details. % % You should have received a copy of the GNU General Public License % along with ONSAS.  If not, see https://www.gnu.org/licenses/. %","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"# Uniaxial Extension Solid example\n\n[![Octave script](https://img.shields.io/badge/script-url-blue)](https://github.com/ONSAS/ONSAS/blob/master/examples/uniaxialExtension/uniaxialExtension.m)\n\nIn this tutorial example an elastic solid is submitted to a uniaxial extension test. The problem is inspired by Exercise 4 from section 6.5 in (Holzapfel,2000). The geometry and tension applied are shown in the figure, where the $Lx$, $Ly$ and $Lz$ are the dimensions and the tension $p$ is applied on the face $x=Lx$, as nominal traction (see (Holzapfel,2000)).\n","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"@raw html <img src=\"../../assets/diagramSolidUniaxial.svg\" alt=\"structure diagram\" width=\"500\"/>","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"\n## Analytic solution\n\nLet us consider that a uniform deformation is produced, with a nonzero axial stretch $\\alpha$ and nonzero transversal stretch $\\beta$. The corresponding deformation gradient and Green-Lagrange strain tensor are given by:","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"math \\textbf{F} = \\left[ \\begin{matrix} \\alpha & 0 & 0 \\ 0 & \\beta & 0 \\ 0 & 0 & \\beta \\end{matrix} \\right] \\qquad \\textbf{E} = \\left[  \\begin{matrix} \\frac{1}{2} \\left(\\alpha^2 -1\\right) & 0 & 0 \\ 0 &  \\frac{1}{2} \\left(\\beta^2 -1\\right) & 0 \\ 0 & 0 &  \\frac{1}{2} \\left(\\beta^2 -1\\right) \\end{matrix} \\right]","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"The second Piola-Kirchhoff tensor $\\textbf{S}$ is given by","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"math \\textbf{S}( \\textbf{E} ) = p1 tr(\\textbf{E}) \\textbf{I} + 2 p2 \\textbf{E}","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":" then, using the relation $\\textbf{P}=\\textbf{F}\\textbf{S}$, the $P_{yy}$ component is computed and set to zero (using the boundary conditions)","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"math P{yy}( \\textbf{E} ) = p1 \\beta \\left(              \\frac{1}{2} \\left(\\alpha^2 -1 \\right) + \\left( \\beta^2 -1\\right)  \\right) + 2 p_2 \\beta (\\frac{1}{2} \\left(\\beta^2 -1 \\right)) = 0","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"then, using that $\\beta\\neq0$ (since $\\text{det}( \\textbf{F} ) \\neq0$), we obtain","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"math  p1 \\frac{1}{2} \\left(\\alpha^2 -1 \\right)  = - (p1+p_2) \\left(\\beta^2 -1 \\right)","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":" then using the relation between the Lamé parameters $p_2$ and $p_1$ and the Young modulus and Poisson ratio, we obtain:\n","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"math  \\left(\\beta^2 -1 \\right) = -\\nu \\left(\\alpha^2 -1 \\right).","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"\n The axial component of the nominal stress is","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"math P{xx}( \\textbf{E} ) = p1 \\alpha \\left(              \\frac{1}{2} \\left(\\alpha^2 -1 \\right) + \\left( \\beta^2 -1\\right)  \\right) + 2 p_2 \\alpha (\\frac{1}{2} \\left(\\alpha^2 -1 \\right)) = 0","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":" and substituting we obtain\n","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"math P{xx}( \\alpha ) = p1 \\alpha \\frac{1-2\\nu}{2} \\left(\\alpha^2 -1 \\right) + p_2 \\alpha \\left(\\alpha^2 -1 \\right) =  \\left( \\frac{E \\nu}{(1+\\nu)2}  + \\frac{E}{(1+\\nu)2} \\right)  \\alpha \\left(\\alpha^2 -1 \\right)","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":" thus, considering the axial displacement $u$ and using the stretch definition $\\alpha = (1+u/Lx)$, we obtain","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"math P_{xx}( u ) =  \\frac{E}{2}  \\left( \\left( 1+\\frac{u}{Lx} \\right)^3 - \\left( 1+ \\frac{u}{Lx} \\right) \\right)","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":" where $u$ is the $x$ displacement of the points located on face $x=Lx$.\n\n## Numerical solution: case 1\n---\nBefore defining the structs, the workspace is cleaned, the ONSAS directory is added to the path and scalar geometry and material parameters are defined.","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"close all; if ~strcmp(getenv('TESTS_RUN'), 'yes')   clear all; end % add path addpath(genpath([pwd '/../../src'])); % scalar parameters E = 1; nu = 0.3; p = 3; Lx = 2; Ly = 1; Lz = 1;","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"\n\n### MEB parameters\n\n#### materials\n The material of the solid considered is the Saint-Venant-Kirchhoff with Lamé parameters computed as","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"lambda = E * nu / ((1 + nu) * (1 - 2 * nu)); mu = E / (2 * (1 + nu));","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":" since only one material is considered, a scalar struct is defined as follows","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"materials                 = struct(); materials.modelName  = 'SVK'; materials.modelParams = [lambda mu];","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"\n#### elements\n In this model two kinds of elements are used: `tetrahedron` for the solid and `triangle` for introducing the external loads. Since two kinds of elements are used, the struct have length 2:","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"elements             = struct(); elements(1).elemType = 'triangle'; elements(2).elemType = 'tetrahedron';","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"\n#### boundaryConds\n in this case four BCs are considered, one corresponding to a load and three to displacements.\n the first BC introduced is a load, then the coordinate system, loadfactor time function and base load vector are defined","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"boundaryConditions             = struct(); boundaryConds(1).loadsCoordSys = 'global'; boundaryConds(1).loadsTimeFact = @(t) p * t; boundaryConds(1).loadsBaseVals = [1 0 0 0 0 0];","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":" the other BCs have imposed displacements","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"boundaryConds(2).imposDispDofs = [1]; boundaryConds(2).imposDispVals =  0; % boundaryConds(3).imposDispDofs = [3]; boundaryConds(3).imposDispVals =  0; % boundaryConds(4).imposDispDofs = [5]; boundaryConds(4).imposDispVals =  0; %","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"\n#### initialConds\n since no initial non-homogeneous initial conditions are used, an empty struct is used .","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"initialConds = struct();","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"\n### Mesh\n A simple hand-made 8-node mesh, with 6 tetrahedrons is considered\n","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"@raw html <img src=\"https://raw.githubusercontent.com/ONSAS/ONSAS_docs/master/docs/src/solidCubeMeshHTML.svg\" alt=\"mesh diagram\" width=\"500\"/>","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"@raw latex \\begin{center} \\def\\svgwidth{0.6\\textwidth} \\input{solidCubeMeshPDF.pdf_tex} \\end{center}","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":" The node coordinates matrix is given by the following","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"mesh             = struct(); mesh.nodesCoords = [0    0    0; ...                     0    0   Lz; ...                     0   Ly   Lz; ...                     0   Ly    0; ...                     Lx   0    0; ...                     Lx   0   Lz; ...                     Lx  Ly   Lz; ...                     Lx  Ly    0];","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":" and the connectivity cell is defined as follows with the four MEB parameters for each element followed by the indexes of the nodes of each element. All the eight triangle elements are considered with no material (since they are used only to include load) and the following six elements are solid SVK material tetrahedrons.","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"mesh.conecCell = {[0 1 1     5 8 6]; ... % loaded face                   [0 1 1     6 8 7]; ... % loaded face                   [0 1 2     4 1 2]; ... % x=0 supp face                   [0 1 2     4 2 3]; ... % x=0 supp face                   [0 1 3     6 2 1]; ... % y=0 supp face                   [0 1 3     6 1 5]; ... % y=0 supp face                   [0 1 4     1 4 5]; ... % z=0 supp face                   [0 1 4     4 8 5]; ... % z=0 supp face                   [1 2 0     1 4 2 6]; ... % tetrahedron                   [1 2 0     6 2 3 4]; ... % tetrahedron                   [1 2 0     4 3 6 7]; ... % tetrahedron                   [1 2 0     4 1 5 6]; ... % tetrahedron                   [1 2 0     4 6 5 8]; ... % tetrahedron                   [1 2 0     4 7 6 8]  ... % tetrahedron                  };","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"\n### Analysis parameters\n","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"analysisSettings               = struct(); analysisSettings.methodName    = 'newtonRaphson'; analysisSettings.stopTolIts    = 30; analysisSettings.stopTolDeltau = 1.0e-8; analysisSettings.stopTolForces = 1.0e-8; analysisSettings.finalTime      = 1; analysisSettings.deltaT        = .125;","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"\n### Output parameters","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"otherParams              = struct(); otherParams.plotsformat = 'vtk'; otherParams.problemName  = 'uniaxialExtensionHandMadeMesh';","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"[modelCurrSol, modelProperties, BCsData] = ONSAS_init(materials, elements, boundaryConds, initialConds, mesh, analysisSettings, otherParams); %","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"After that the structs are used to perform the numerical time analysis","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"[matUs, loadFactorsMat, solutions] = ONSAS_solve(modelCurrSol, modelProperties, BCsData);","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"\n### Analytic solution computation","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"analyticFunc = @(w) 1 / p * E * 0.5 * ((1 + w / Lx).^3 - (1 + w / Lx));","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"analyticCheckTolerance = 1e-6; analyticFunc           = @(w) E * 0.5 * ((1 + w / Lx).^3 - (1 + w / Lx)); controlDisps = matUs(6 * 6 + 1, :); analyticVals = analyticFunc(controlDisps); controlDispsValsCase1         = controlDisps; loadFactorAnalyticalValsCase1 = analyticVals; loadFactorNumericalValsCase1  = loadFactorsMat;","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"\n## Numerical solution: case 2\nIn this analysis case, the mesh information is read from a mesh file generated by\n the tool [GMSH](https://gmsh.info/).\n The pressure is applied using local coordinates and the stiffness\n matrix is computed using the complex-step method.\n","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"otherParams.problemName = 'uniaxialExtensionGMSHComplexStep';","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":" this auxiliar line sets the right path to the testing environment","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"basemsh = ''; if strcmp(getenv('TESTSRUN'), 'yes') && isfolder('examples')   basemsh = ['.' filesep 'examples' filesep 'uniaxialExtension' filesep]; end % [mesh.nodesCoords, mesh.conecCell] = meshFileReader([basemsh 'geometry_uniaxialExtension.msh']); boundaryConds(1).loadsCoordSys = 'local'; boundaryConds(1).loadsBaseVals = [0 0 0 0 1 0]; elements(2).elemTypeParams = [2];","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"[modelCurrSol, modelProperties, BCsData] = ONSAS_init(materials, elements, boundaryConds, initialConds, mesh, analysisSettings, otherParams); %","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"After that the structs are used to perform the numerical time analysis","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"[matUs, loadFactorsMat, solutions] = ONSAS_solve(modelCurrSol, modelProperties, BCsData);","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"controlDisps = matUs(6 * 6 + 1, :); analyticVals = analyticFunc(controlDisps); controlDispsValsCase2         = controlDisps; loadFactorAnalyticalValsCase2 = analyticVals; loadFactorNumericalValsCase2  = loadFactorsMat;","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"aux1 = loadFactorNumericalValsCase1' - loadFactorAnalyticalValsCase1; aux2 = loadFactorNumericalValsCase2' - loadFactorAnalyticalValsCase1;","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"verifBoolean = ...       (norm(aux1) / norm(loadFactorNumericalValsCase1) < analyticCheckTolerance) && ...       (norm(aux2) / norm(loadFactorNumericalValsCase1) < analyticCheckTolerance);","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"\n\n## Plot\nThe numerical and analytic solutions are plotted.","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"lw = 2.0; ms = 11; plotfontsize = 18; figure; hold on; grid on; plot(controlDispsValsCase1, loadFactorAnalyticalValsCase1, 'r-x', 'linewidth', lw, 'markersize', ms); plot(controlDispsValsCase1, loadFactorNumericalValsCase1,  'k-o', 'linewidth', lw, 'markersize', ms); plot(controlDispsValsCase2, loadFactorNumericalValsCase2,  'g-s', 'linewidth', lw, 'markersize', ms); labx = xlabel('Displacement'); laby = ylabel('\\lambda(t)'); legend('Analytic', 'Numeric-1', 'Numeric-2', 'location', 'North'); set(gca, 'linewidth', 1.0, 'fontsize', plotfontsize); set(labx, 'FontSize', plotfontsize); set(laby, 'FontSize', plotfontsize); title('uniaxial extension test'); if length(getenv('TESTSRUN')) > 0 && strcmp(getenv('TESTSRUN'), 'yes')   fprintf('\\ngenerating output png for docs.\\n');   print('output/verifUniaxial.png', '-dpng'); else   fprintf('\\n === NOT in docs workflow. ===\\n'); end","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"","category":"page"},{"location":"examples/uniaxialExtension/","page":"Uniaxial extension","title":"Uniaxial extension","text":"@raw html <img src=\"../../assets/generated/verifUniaxial.png\" alt=\"plot check\" width=\"500\"/> ```","category":"page"},{"location":"#Introduction","page":"Home","title":"Introduction","text":"","category":"section"},{"location":"","page":"Home","title":"Home","text":"(Image: tests) (Image: License)","category":"page"},{"location":"#What-is-ONSAS?","page":"Home","title":"What is ONSAS?","text":"","category":"section"},{"location":"","page":"Home","title":"Home","text":"ONSAS is an Open Nonlinear Structural Analysis Solver for GNU-Octave/Matlab. It consists in a set of implementations of numerical methods for static/dynamic and linear/non-linear analysis of structures. The first version was developed for educational purposes and published in a Structural Analysis handbook for a graduate course taught at the School of Engineering of Universidad de la República. The current version allows to perform a diverse set of simulations and it has been used in specific research applications.","category":"page"},{"location":"#Publications-using-ONSAS","page":"Home","title":"Publications using ONSAS","text":"","category":"section"},{"location":"","page":"Home","title":"Home","text":"Journal articles using ONSAS:","category":"page"},{"location":"","page":"Home","title":"Home","text":"2024, A. Villié, M. Vanzulli, J.M. Pérez Zerpa, J. Vétel, S. Etienne, F.P. Gosselin, Modeling vortex-induced vibrations of branched structures by coupling a 3D-corotational frame finite element formulation with wake-oscillators, Journal of Fluids and Structures url\n2023, M. Vanzulli, J. M. Pérez Zerpa, A co-rotational formulation for quasi-steady aerodynamic nonlinear analysis of frame structures, Heliyon url\n2022, M. Forets, D. Freire, J. M. Pérez Zerpa, Combining set propagation with finite element methods for time integration in transient solid mechanics problems, Computers & Structures url","category":"page"},{"location":"","page":"Home","title":"Home","text":"Theses using ONSAS:","category":"page"},{"location":"","page":"Home","title":"Home","text":"2021, M. Vanzulli, Implementación de una formulación corrotacional en dinámica no lineal y aplicación al modelado de líneas de transmisión eléctrica url\n2021, A. Teliz, Optimización de torres de alta tensión y su análisis frente a vientos de alta intensidad url","category":"page"},{"location":"#Some-academic-examples","page":"Home","title":"Some academic examples","text":"","category":"section"},{"location":"#A-deployable-ring","page":"Home","title":"A deployable ring","text":"","category":"section"},{"location":"","page":"Home","title":"Home","text":"This nonlinear static problem is introduced in (Goto et. al, 1992) and also considered in (Battini and Pacoste, 2002).","category":"page"},{"location":"","page":"Home","title":"Home","text":"<img src=\"https://github.com/ONSAS/ONSAS/blob/master/docs/src/assets/deployableRing.gif?raw=true\">","category":"page"},{"location":"#Right-Angle-Cantilever","page":"Home","title":"Right-Angle Cantilever","text":"","category":"section"},{"location":"","page":"Home","title":"Home","text":"This nonlinear dynamic analysis problem is introduced in (Simo and Vu-Quoc, 1988) and also considered as Example 1 in (Le et. al., 2014).","category":"page"},{"location":"","page":"Home","title":"Home","text":"<img src=\"https://github.com/ONSAS/ONSAS/blob/master/docs/src/assets/rightAngleCantilever.gif?raw=true\" alt=\"right-angle animation\">","category":"page"},{"location":"#A-simple-propeller-model","page":"Home","title":"A simple propeller model","text":"","category":"section"},{"location":"","page":"Home","title":"Home","text":"This problem is based on one of the examples presented in (Vanzulli and Pérez Zerpa, 2023).","category":"page"},{"location":"","page":"Home","title":"Home","text":"<img src=\"https://github.com/ONSAS/ONSAS/blob/master/docs/src/assets/propeller.gif?raw=true\" alt=\"propeller animation\">","category":"page"},{"location":"#A-tower-model","page":"Home","title":"A tower model","text":"","category":"section"},{"location":"","page":"Home","title":"Home","text":"<img src=\"https://github.com/ONSAS/ONSAS_docs/blob/master/gifs/tower.gif?raw=true\" alt=\"tower animation\">","category":"page"},{"location":"#A-beam/truss-pendulum","page":"Home","title":"A beam/truss pendulum","text":"","category":"section"},{"location":"","page":"Home","title":"Home","text":"<img src=\"https://raw.githubusercontent.com/mvanzulli/Tex_CorrotationalDynamicTL_TesisMV/main/Presentacion/Videos/3.gif\" alt=\"beam truss pendulum\">","category":"page"},{"location":"#Contact","page":"Home","title":"Contact","text":"","category":"section"},{"location":"","page":"Home","title":"Home","text":"You can publicly post in the discussion section or contact privately sending an e-mail to jorgepz [AT] fing.edu.uy .","category":"page"},{"location":"#Contributors-and-License","page":"Home","title":"Contributors and License","text":"","category":"section"},{"location":"#License","page":"Home","title":"License","text":"","category":"section"},{"location":"","page":"Home","title":"Home","text":"The code is distributed under a GNU-GPL 3.0 license.","category":"page"},{"location":"#Authors","page":"Home","title":"Authors","text":"","category":"section"},{"location":"","page":"Home","title":"Home","text":"The authorship of each version is (or tends to be) based on the criteria defined by the JOSS journal. The co-authors have collaborated in tasks such as: design, development or extensive documentation contributions.","category":"page"},{"location":"","page":"Home","title":"Home","text":"Jorge M. Pérez Zerpa (1), leaded and managed the design and development of the code, developed the assembly functions, nonlinear truss element formulation, nonlinear static analysis function, designed and co-authored Newmark's method function, input and output functions, leaded the generation of the documentation.\nMauricio Vanzulli (2) co-developed the Newmark's method functions and scripts, developed input files for the dynamic analysis examples. Developed the nonlinear dynamic co-rotational frame element function, its validation and integration with the VIV function. \nJoaquín Viera (1), leaded the development of the Linear Analysis module and input files, collaborated in the design and development of the input reading and output generation modules, leaded the development of a GUI.\nAlexandre Villié (3) developed the current Vortex-Induced-Vibrations Wake Oscillator model. Also contributed in the validation of this function in the integration with the co-rotational frame element.\nMarcelo Forets (4) made relevant contributions to application of software technology tools, in particular, the documentation generation workflow. Contributed also to the implementation of the Neo-Hookean solid model.\nJean-Marc Battini (4), contributed functions for the computation of static internal forces of the nonlinear co-rotational frame element.\nJ. Bruno Bazzano (1), contributed to the design/development of the buckling analysis modules, co-designed the initial version of the code, developed and implemented validation examples, validated the HHT implementation.","category":"page"},{"location":"","page":"Home","title":"Home","text":"Affiliations:","category":"page"},{"location":"","page":"Home","title":"Home","text":"Instituto de Estructuras y Transporte, Facultad de Ingeniería, Universidad de la República, Montevideo, Uruguay\nInstituto de Ingeniería Mecánica y Producción Industrial, Facultad de Ingeniería, Universidad de la República, Montevideo, Uruguay.\nDepartment of Mechanical Engineering, Polytechnique Montréal, Montréal, Canada.\nCentro Universitario Regional Este, Universidad de la República, Maldonado, Uruguay\nDepartment of Civil and Architectural Engineering, KTH Royal Institute of Technology, Stockholm, Sweden","category":"page"},{"location":"#Contributions-and-Acknowledgments","page":"Home","title":"Contributions and Acknowledgments","text":"","category":"section"},{"location":"","page":"Home","title":"Home","text":"Santiago Correa made contributions to examples, mainly beamLinearVibration, and corrected the expression of a parameter of the alpha-HHT method. Professor Sebastian Toro, provided functions for reading dxf files, which were part of ONSAS until version 0.2.6.","category":"page"},{"location":"","page":"Home","title":"Home","text":"Prof. Pérez Zerpa would like to thank: Prof. Frédérick Gosselin for his support during the initial contributions of Alexandre Villié, Prof. Eduardo de Souza Neto for his comments on the arc-length norm computation, and Pablo Blanco, Gonzalo Ares and Gonzalo Maso Talou for so many discussions during early stages of the design of the code.","category":"page"},{"location":"","page":"Home","title":"Home","text":"The development of ONSAS has been partially supported by funds provided by the following agencies/projects:","category":"page"},{"location":"","page":"Home","title":"Home","text":"Comisión de Investigación Científica (CSIC) (project: Definición de estrategias para la aplicación de métodos de identificación de material al diagnóstico no invasivo de Cáncer de mama, manager, Prof. Pérez Zerpa),\nComisión Sectorial de Enseñanza (project: Rediseño de prácticas de enseñanza y evaluación en Resistencia de Materiales, manager, Prof. Pérez Zerpa),\nAgencia Nacional de Investigación e Innovación (project VIOLETA, code FSE_1_2016_1_131837, manager, Prof. Gabriel Usera).","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"% Copyright 2024, ONSAS Authors (see documentation) % % This file is part of ONSAS. % % ONSAS is free software: you can redistribute it and/or modify % it under the terms of the GNU General Public License as published by % the Free Software Foundation, either version 3 of the License, or % (at your option) any later version. % % ONSAS is distributed in the hope that it will be useful, % but WITHOUT ANY WARRANTY; without even the implied warranty of % MERCHANTABILITY or FITNESS FOR A PARTICULAR PURPOSE.  See the % GNU General Public License for more details. % % You should have received a copy of the GNU General Public License % along with ONSAS.  If not, see https://www.gnu.org/licenses/. %","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"# Linear Dynamic Vibration of a Simply Supported Beam\n\n[![Octave script](https://img.shields.io/badge/script-url-blue)](https://github.com/ONSAS/ONSAS/blob/master/examples/beamLinearVibration/beamLinearVibration.m)\n\nIn this tutorial, the dynamic response of a simply supported beam is computed using ONSAS with the linear elastic and the co-rotational formulations. The aim of this example is to verify the numerical implementations using an analytic solution.\n\nThe problem consists in a beam with pinned nodes in both ends. Two loads of magnitude $F(t) = f_o \\sin(wt)$ are applied in the middle point as it is shown in the figure, where $f_o$ is the force magnitude amplitude and $\\omega$ is the force angular frequency.\n","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"@raw html <img src=\"../../assets/beamDynamicVibration.svg\" alt=\"structure diagram\" width=\"500\"/>","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"\nBefore defining the structs, the workspace is cleaned and the ONSAS directory is added to the path","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"close all; if ~strcmp(getenv('TESTS_RUN'), 'yes')   clear all; end addpath(genpath([pwd '/../../src']));","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"\nThe material scalar parameters are set.","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"E = 200e9; nu = 0.3; rho = 700;","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"The cross-section of the beam is rectangular. The widths and other geometry scalar parameters are computed.","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"l = 10; ty = .3; tz = .1;                  % length of rectangular cross-section widths Iyy = ty * tz^3 / 12; Izz = tz * ty^3 / 12; % bending inertias numElements = 10; % Number of elements","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":" Time and applied force parameters are","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"Fo     = 100; % force magnitude (N) w      = 2; % force angular frequency (rad/s) tf     = 8; % s deltat = 0.1; % s","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":" The middle node is computed","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"assert(rem(numElements, 2) == 0, 'the number of elements must be even.'); appNode    = (numElements) / 2 + 1; appNodePos = (appNode - 1) * l / numElements;","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"\n## Analytic solution\n\n The governing equations for the deflection $v$ of a beam with uniform cross-section, density and Young modulus with a transversal distributed applied load $q$ is given by","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"math  EI \\frac{\\partial^4 v}{\\partial x^4}(x,t) + \\rho A \\frac{\\partial^2 v}{\\partial t^2}(x,t) = q(x,t)","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"and using a Fourier decomposition and following the process explained in chapter 10 of _Mechanical Vibrations_ (5th Edition; Rao Singiresu) we obtain the analytic solution for the displacement of our problem","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"math  v(x,t) = \\frac{2fo}{\\rho A l} \\sum{n=1}^{\\infty} \\frac{1}{w{n}^2 - w^2} \\sin\\left(\\frac{n \\pi a}{l} \\right) \\sin\\left(\\frac{n \\pi x}{l} \\right)\\sin(wt)","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"where $w_n$ are natural frequencies of the vibration for mode $n$ (computed for each transversal direction).\n\nThe solution can be numerically computed setting a mesh of spatial poins and a vector of times\n","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"ts = 0:deltat:tf; % times vector xs = 0:l / numElements:l; % beam mesh ns = 1:10; % modes","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"\n As well as the vector of natural frequencies\n","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"wnY = ((ns * pi).^2) * sqrt(E * Izz / rho / (ty * tz) / (l^4)); % Natural frecuency direction Y wnZ = ((ns * pi).^2) * sqrt(E * Iyy / rho / (ty * tz) / (l^4)); % Natural frecuency direction Z","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"\n The values of the analytic solution are computed as\n","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"analyticDisY = 0; analyticDisZ = 0; analySolPos = appNodePos;  % the analytic solution is computed at the point of application of the load for i = 1:length(ns)   analyticDisY = analyticDisY + (1 / (wnY(i)^2 - w^2)) * sin(i * analySolPos / l * pi) * sin(i * pi * appNodePos / l) * sin(w * ts)';   analyticDisZ = analyticDisZ + (1 / (wnZ(i)^2 - w^2)) * sin(i * analySolPos / l * pi) * sin(i * pi * appNodePos / l) * sin(w * ts)'; end analyticDisY = analyticDisY * (2 * Fo / (rho * ty * tz * l)); analyticDisZ = analyticDisZ * (2 * Fo / (rho * ty * tz * l));","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"\n## Numerical solution\n### MEB parameters\n\nThe modelling of the structure begins with the definition of the Material-Element-BoundaryConditions (MEB) parameters.\n\n### materials\n Since the example contains only one rod and no nodal masses are used, only one `materials` struct is defined. The first analysis is done using the co-rotational formulation","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"materials = struct(); materials.modelName  = 'elastic-rotEngStr'; materials.modelParams = [E nu]; materials.density         = rho;","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"\n### elements\n\nTwo different types of elements are considered, `node` and `beam`. The nodes will be assigned in the first entry (index $1$) and the beam at index $2$. The elemType field is then:","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"elements = struct(); elements(1).elemType = 'node'; elements(2).elemType = 'frame';","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":" for the crossSection, a frame element of rectangular-cross section with $t_y$ and $t_z$ dimensions in $y$ and $z$ directions is set, then the elemTypeGeometry field is:","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"elements(2).elemCrossSecParams = { 'rectangle', [ty tz] };","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":" The consistent mass approach is considered for the dynamic analysis","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"elements(2).massMatType = 'consistent';","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"\n### boundaryConditions\n\n The elements are submitted to two different BC settings. The first BC corresponds to the fixed points","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"boundaryConds = struct(); boundaryConds(1).imposDispDofs = [1 2 3 5]; boundaryConds(1).imposDispVals = [0 0 0 0];","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":" and the second corresponds to a time dependant external force","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"boundaryConds(2).loadsCoordSys = 'global'; boundaryConds(2).loadsTimeFact = @(t) Fo * sin(w * t); boundaryConds(2).loadsBaseVals = [0 0 1 0 1 0];","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"\n\n### mesh parameters\nThe coordinates of the nodes of the mesh are given by the matrix:","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"mesh = struct(); mesh.nodesCoords = [(0:(numElements))' * l / numElements  zeros(numElements + 1, 2)];","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"The connectivity is introduced using the _conecCell_ cell. Each entry of the cell contains a vector with the four indexes of the MEB parameters, followed by the indexes of the nodes of the element (node connectivity). For didactical purposes each element entry is commented. First the cell is initialized:","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"mesh.conecCell = { };","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":" then the first two nodes are defined, both with material zero (since nodes dont have material), the first element type (the first entry of the cells of the _elements_ struct), and the first entry of the cells of the boundary conditions struct. Finally the node index is included.","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"mesh.conecCell{ 1, 1 } = [0 1 1  1];","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":" the following case only differs in the boundary condition and the node number","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"mesh.conecCell{ 2, 1 } = [0 1 1  numElements + 1];","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":" the following case only differs in the boundary condition and the node number","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"mesh.conecCell{ 3, 1 } = [0 1 2  appNode];","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":" the beam elements are formed by the first material, the second type of element, and no boundary conditions are applied to any element.","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"for i = 1:numElements   mesh.conecCell{ i + 3, 1 } = [1 2 0   i i + 1]; end","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"\n### initial Conditions\n homogeneous initial conditions are considered, then an empty struct is set:","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"initialConds = struct();","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"### analysisSettings","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"analysisSettings               = struct(); analysisSettings.methodName    = 'newmark'; analysisSettings.deltaT        =   deltat; analysisSettings.finalTime     =   tf; analysisSettings.stopTolDeltau =   1e-8; analysisSettings.stopTolForces =   1e-8; analysisSettings.stopTolIts    =   10;","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"\n### otherParams","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"otherParams = struct(); otherParams.problemName = 'coRotationaluniformDynamicBeam';","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"\n ONSAS execution","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"[modelCurrSol, modelProperties, BCsData] = ONSAS_init(materials, elements, boundaryConds, initialConds, mesh, analysisSettings, otherParams); %","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"After that the structs are used to perform the numerical time analysis","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"[coRotMatUs, loadFactorsMat, modelSolutions] = ONSAS_solve(modelCurrSol, modelProperties, BCsData);","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"\n The second analysis case implements the linear elastic formulation","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"materials.modelName  = 'elastic-linear'; otherParams.problemName = 'elastic-linearuniformDynamicBeam';","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"\n ONSAS execution","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"[modelCurrSol, modelProperties, BCsData] = ONSAS_init(materials, elements, boundaryConds, initialConds, mesh, analysisSettings, otherParams); %","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"After that the structs are used to perform the numerical time analysis","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"[linElasMatUs, loadFactorsMat, modelSolutions] = ONSAS_solve(modelCurrSol, modelProperties, BCsData);","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"\n the report is generated","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"outputReport(modelProperties.outputDir, modelProperties.problemName);","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"\n### Error estimation","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"dofYendNode = 6 * (appNode) - 3; dofZendNode = 6 * (appNode) - 1;","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"\n error computed for each method in the application node of the external force","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"diflinearDispUy = linElasMatUs(dofYendNode, :)' - analyticDisY; diflinearDispUz = linElasMatUs(dofZendNode, :)' - analyticDisZ; difcoRotDispUy  = coRotMatUs(dofYendNode, :)'   - analyticDisY; difcoRotDispUz  = coRotMatUs(dofZendNode, :)'   - analyticDisZ;","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"errlinearDispUy = norm(diflinearDispUy, 1) / norm(analyticDisY, 1); errcoRotDispUy  = norm(difcoRotDispUy, 1) / norm(analyticDisY, 1); errlinearDispUz = norm(diflinearDispUz, 1) / norm(analyticDisZ, 1); errcoRotDispUz  = norm(difcoRotDispUz, 1) / norm(analyticDisZ, 1);","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"\n the numerical resolution is validated for both method and both directions.","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"verifBoolean =  (errlinearDispUy <  5e-2) && (errcoRotDispUy  <  5e-2) && ...               (errlinearDispUz <  5e-2) && (errcoRotDispUz  <  5e-2);","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"\n Plot parameters:","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"lw = 2.0; lw2 = 1.0; ms = 11; plotfontsize = 18;","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":" plot y-axis linear, co-rotational and analytic result","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"figure; hold on; grid on; plot(ts, coRotMatUs(dofYendNode, :), 'r-x', 'linewidth', lw, 'markersize', ms); plot(ts, linElasMatUs(dofYendNode, :), 'k-o', 'linewidth', lw, 'markersize', ms); plot(ts, analyticDisY, 'b', 'linewidth', lw, 'markersize', ms); legend('coRotational{disp}', 'elastic-linear{disp}', 'Analytic_{disp}', 'location', 'eastoutside'); labx = xlabel('time (s)'); laby = ylabel('displacement (m)'); set(gca, 'linewidth', lw2, 'fontsize', plotfontsize); set(labx, 'FontSize', plotfontsize); set(laby, 'FontSize', plotfontsize); print('output/Uy', '-dpng');","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":" plot z-axis linear, co-rotational and analytic result","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"figure; hold on; grid on; plot(ts, coRotMatUs(dofZendNode, :), 'r-x', 'linewidth', lw, 'markersize', ms); plot(ts, linElasMatUs(dofZendNode, :), 'k-o', 'linewidth', lw, 'markersize', ms); plot(ts, analyticDisZ, 'b', 'linewidth', lw, 'markersize', ms); legend('coRotational{disp}', 'elastic-linear{disp}', 'Analytic_{disp}', 'location', 'eastoutside'); labx = xlabel('time (s)'); laby = ylabel('displacement (m)'); set(gca, 'linewidth', lw2, 'fontsize', plotfontsize); set(labx, 'FontSize', plotfontsize); set(laby, 'FontSize', plotfontsize); print('output/Uy.png', '-dpng'); % print('../../docs/src/assets/beamDynamicVibrationVerifUy.png','-dpng')","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"","category":"page"},{"location":"examples/beamLinearVibration/","page":"Linear beam vibration","title":"Linear beam vibration","text":"@raw html <img src=\"../../assets/beamDynamicVibrationVerifUy.png\" alt=\"structure diagram\" width=\"500\"/> ```","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"% Copyright 2024, ONSAS Authors (see documentation) % % This file is part of ONSAS. % % ONSAS is free software: you can redistribute it and/or modify % it under the terms of the GNU General Public License as published by % the Free Software Foundation, either version 3 of the License, or % (at your option) any later version. % % ONSAS is distributed in the hope that it will be useful, % but WITHOUT ANY WARRANTY; without even the implied warranty of % MERCHANTABILITY or FITNESS FOR A PARTICULAR PURPOSE.  See the % GNU General Public License for more details. % % You should have received a copy of the GNU General Public License % along with ONSAS.  If not, see https://www.gnu.org/licenses/. %","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"# Plane strain ring example\n\n[![Octave script](https://img.shields.io/badge/script-url-blue)](https://github.com/ONSAS/ONSAS/blob/master/examples/ringPlaneStrain/ringPlaneStrain.m)\n\n In this example a hollow cylinder submitted to an internal pressure $p_i$ as shown in diagram depicted below is considered. The length of the cylinder is $L_z $ m and the internal and external radious are $R_i$ and $R_e$, respectively.\n","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"@raw html <img src=\"../../assets/linearCylinderPlaneStrain/ilusCylinderPlaneStrain.svg\" alt=\"linear cylinder diagram\" width=\"500\"/>","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"\n Before defining the structs, the workspace is cleaned, the ONSAS directory is added to the path and scalar geometry and material parameters are defined:","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"close all; if ~strcmp(getenv('TESTS_RUN'), 'yes')   clear all; end % add path addpath(genpath([pwd '/../../src'])); % scalar parameters % E = 1e6 ; nu = 0.3 ; p = 30e3 ; L = .75 ; Re = 0.15 ; Ri = 0.1 ; E = 210; nu = 0.3; p = 0.01; L = .75; global Re global Ri Re = 200; Ri = 100;","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"## Linear analysis\n### Analytic solution\n\n The solution displacement field is extracted from chapter 4 of  (Timoshenko and Goodier, Theory of Elasticity, 3rd edition). The Navier's equation, imposing no temperature variation, no volumetric forces, and considering a radial dispalcement field leads to:","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"math   \\nabla (\\nabla . \\textbf{u}(r,\\theta,z) )  = 0","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":" Due to the symmetry of the problem $\\mathbf{\\mathit{u_{\\theta}}} = 0 $ and also $\\mathbf{ \\mathit{ \\textbf{u} (r,\\theta,z) } } = \\mathbf{ \\mathit{ \\textbf{u}(r,z) } } $. Thus, according to the boundary conditions stated above $\\mathit{u_z(r,z)=0}$ and the radial displacements field $\\mathit{u_r(r)}$ only varies with $r$. Thereafter by imposing the boundary conditions stated above and substituting ($E$, $\\nu$) into Lamé parameters ($\\lambda=\\frac{ E\\nu }{(1 + 2\\nu )(1 - 2\\nu )}$ and $\\mu=\\frac{ E\\nu }{(1 + 2\\nu )}$) we obtain:","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"math  ur(r) = Ar + \\dfrac{B}{r}  \\\n A = \\dfrac{(1+\\nu)(1-2\\nu)Ri^2pi}{E(Re^2-Ri^2)}, \\quad  B = \\dfrac{(1+\\nu)Ri^2Re^2pi}{E(Re^2-Ri^2)}","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"### Numerical solution\n\n#### MEB parameters\n\n##### materials\n The constitutive behavior of the material considered is isotropic linear elastic.\n Since only one material is considered, the structs defined for the materials contain only one entry:","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"materials = struct(); materials.modelName  = 'elastic-linear'; materials.modelParams =  [E nu];","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"\n##### elements\n\n In this plane model, three kinds of elements are used: `triangle` for the solid, `edges` to add pressure loads and `nodes` to set additional boundary conditions for the numerical resolution. Since three kinds of elements are used, the struct has length 3:","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"elements = struct(); elements(1).elemType           = 'node'; elements(2).elemType           = 'edge'; elements(2).elemCrossSecParams = L; elements(3).elemType           = 'triangle'; elements(3).elemTypeParams     = 2; elements(3).elemCrossSecParams = L;","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":" where `elemCrossSecParams` field sets the thickness of the edge and `elemTypeParams` sets the plane strain triangle element.\n\n##### boundaryConds\n Three BCs are considered, one corresponding to a load and two for displacements.\n The first two BCs constrain displacements in $x$ and $y$ global directions respectively:","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"boundaryConds = struct(); boundaryConds(1).imposDispDofs = [1]; boundaryConds(1).imposDispVals = [0]; boundaryConds(2).imposDispDofs = [3]; boundaryConds(2).imposDispVals = [0];","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":" then the third BC corresponds to the pressure. It is introduced in `local` coordinates so the first entry is along the edge (tangent) and the second towards the normal vector obtained by rotating the tangent vector 90 degrees in global axis $z$:","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"boundaryConds(3).loadsCoordSys = 'local'; boundaryConds(3).loadsTimeFact = @(t) t; boundaryConds(3).loadsBaseVals = [0 p];","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"\n\n#### Mesh\n The mesh can be read from the msh file. However, if any changes to the mesh are desired, the .geo file can be edited and the msh file can be re-generated using GMSH.\n","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"@raw html <img src=\"../../assets/linearCylinderPlaneStrain/meshCylinderPlaneStrain.png\" alt=\"mesh plot\" width=\"500\"/>","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":" The element properties are set using labels into GMSH follwing the MEB nomenclature. First `triangle` elements have linear elastic material so entry $1$ of the _materialṣ_ struct is assigned. Then for both `node` and `edge` elements any material is set.\n Next displacement boundary conditions are assigned to the element, since the problem is modeled into $x-y$ plane, a constrain to avoid rotation along $z$ is necessary. This is done fixing $y$ and $x$ displacements (using `boundaryConds(1)` and `boundaryConds(2)` as labels) on points 2 3 4 5.\n Finally the internal pressure is applied on the `edge` elements linked with curves from one to four (Circles 1-4 in Figure). In accordance with the orientation of the curve set in GMSH, the normal vector obtained in local coordinates is $e_r$ so the internal pressure is assigned using `boundaryConds(3)`. Once the mesh is created is read using:","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"basemsh = ''; if strcmp(getenv('TESTSRUN'), 'yes') && isfolder('examples')   basemsh = ['.' filesep 'examples' filesep 'ringPlaneStrain' filesep]; end mesh = struct(); [mesh.nodesCoords, mesh.conecCell] = meshFileReader([basemsh 'ring.msh']);","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"\n#### initialConds\n Any non-homogeneous initial conditions are considered, thereafter an empty struct is set:","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"initialConds = struct();","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"#### Analysis parameters\n\n The Newton-Raphson method is employed to solve 2 load steps. The ratio between `finalTime` and `deltaT` sets the number of load steps used to evaluate `boundaryConds(3).loadsTimeFact` function:","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"analysisSettings = struct(); analysisSettings.methodName    = 'newtonRaphson'; analysisSettings.stopTolIts    = 30; analysisSettings.stopTolDeltau = 1.0e-12; analysisSettings.stopTolForces = 1.0e-12; analysisSettings.finalTime     = 1; analysisSettings.deltaT        = .5;","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"\n#### Output parameters\n","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"otherParams = struct(); otherParams.problemName = 'linearPlaneStrain'; otherParams.plotsformat = 'vtk';","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":" The ONSAS software is executed for the parameters defined above and the displacement solution of each load(time) step is saved in `matUs`matrix:\n","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"[modelCurrSol, modelProperties, BCsData] = ONSAS_init(materials, elements, boundaryConds, initialConds, mesh, analysisSettings, otherParams); %","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"After that the structs are used to perform the numerical time analysis","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"[matUs, loadFactorsMat, modelSolutions] = ONSAS_solve(modelCurrSol, modelProperties, BCsData);","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"\n### Verification\nThe numerical and analytic solutions are compared at the final load step for the internal and external surface (since all the elements on the same surface have the same analytic solution):","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"% internal surface analytic solution A = (p * (1 + nu) * (1 - 2 * nu) * Ri^2) / (E * (Re^2 - Ri^2)); B = (p * (1 + nu) * Ri^2 * Re^2)   / (E * (Re^2 - Ri^2)); analyticValRi = A * Ri + B / Ri; % internal surface numerical solution dofXRi = 1; numericalRi = matUs(dofXRi, end); % external surface analytic solution analyticValRe = A * Re + B / Re; % external surface numerical solution dofXRe = (8 - 1) * 6 + 3; numericalRe = matUs(dofXRe, end);","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"\n The numerical and analytical solution for the internal and external surface are plotted:","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"% plot parameters lw = 2.0; ms = 11; plotfontsize = 10; figure; hold on; grid on; % internal surface plot(matUs(dofXRi, :), loadFactorsMat(:, 3), 'ro', 'linewidth', lw, 'markersize', ms); plot(linspace(0, analyticValRi, length(loadFactorsMat(:, 3))), loadFactorsMat(:, 3), 'k-', 'linewidth', lw, 'markersize', ms); % internal surface plot(matUs(dofXRe, :), loadFactorsMat(:, 3), 'ro', 'linewidth', lw, 'markersize', ms); plot(linspace(0, analyticValRe, length(loadFactorsMat(:, 3))), loadFactorsMat(:, 3), 'k-', 'linewidth', lw, 'markersize', ms); labx = xlabel('Displacement [m]'); laby = ylabel('\\lambda(t)'); legend('Numeric', 'Analytic', 'location', 'East'); set(gca, 'linewidth', 1.2, 'fontsize', plotfontsize); set(labx, 'FontSize', plotfontsize); set(laby, 'FontSize', plotfontsize); print('output/verifLinearRingPlaneStrain.png', '-dpng');","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"@raw html <img src=\"../../assets/linearCylinderPlaneStrain/verifLinearCylinderPlaneStrain.png\" alt=\"verification plot\" width=\"500\"/>","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"\n Finally the deformed configuration is illustrated:","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"@raw html <img src=\"../../assets/linearCylinderPlaneStrain/defLinearCylinderPlaneStrain.png\" alt=\"def plot\" width=\"500\"/>","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"\n## Elastoplastic analysis\n### Semi-analytic solution\n The solution is extracted from Hill (The mathematical theroy of plasticity, 1950).\n The yielding pressure $p_0$ is defined as,","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"math  Y = \\dfrac{2\\sigma{Y,0}}{\\sqrt{3}}  \\\n p0 = \\dfrac{Y}{2}\\left(1+\\dfrac{Ri^2}{Re^2}\\right).","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":" The radial displacement of the outer surface of the ring is given by,","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"math  ur(Re) = \\text{if}~~ p \\leq p0 \\\n \\dfrac{2 p Re}{E \\left( \\dfrac{Re^2}{Ri^2-1}\\right) }( 1-\\nu^2 ) \\\n \\text{else} \\\n \\dfrac{2pRe}{E\\left(\\dfrac{Re^2}{R_i^2-1}\\right)}(1-\\nu^2)","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":" where $c$ denotes the plastic front surface in the ring and is given by the implicit function,","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"math  \\dfrac{p}{Y} = ln\\left(\\dfrac{c}{Ri}\\right) + \\dfrac{1}{2}\\left(1-\\dfrac{c^ 2}{Re^2}\\right)","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"### Numerical solution","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"% scalar parameters E = 210; nu = 0.3; H = 0; sigmaY0 = 0.24; L = .75; p = 0.01;","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"\n\n### MEB parameters\n\n#### materials\n The constitutive behavior of the material considered is isotropic hardening.\n Since only one material is considered, the structs defined for the materials contain only one entry:","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"materials.modelName  = 'isotropicHardening'; materials.modelParams =  [E nu H sigmaY0];","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"\n#### elements\n\n The elements struct is the same as the previous model.\n\n#### boundaryConds\n The BC struct is the same as in the elastic-linear case. However the loadsTimeFact function can be modified to consider unloading as follows.","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"boundaryConds(3).loadsTimeFact = @(t) t * (t <= 19) + (t - (t - 19) * 2) * (t > 19);","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"\n#### initialConds\n Any non-homogeneous initial conditions are considered, thereafter the struc is the same as in the previous example.\n\n### Mesh\n The mesh can be read from the msh file. The same mesh as in the elastic-linear case is considered for this problem.\n","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"Conec = myCell2Mat(mesh.conecCell); elems = size(Conec, 1);","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"\n### Analysis parameters\n\n The Newton-Raphson method is employed to solve 19 load steps. The ratio between `finalTime` and `deltaT` sets the number of load steps used to evaluate `boundaryConds(3).loadsTimeFact` function:","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"analysisSettings.methodName    = 'newtonRaphson'; analysisSettings.stopTolIts    = 30; analysisSettings.stopTolDeltau = 1.0e-8; analysisSettings.stopTolForces = 1.0e-6; analysisSettings.finalTime     = 19; analysisSettings.deltaT        = 1;","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"\n### Output parameters\n","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"otherParams.problemName = 'EPPPlaneStrain'; otherParams.plotsformat = 'vtk';","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":" The ONSAS software is executed for the parameters defined above and the displacement solution of each load(time) step is saved in `matUs`matrix:\n","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"[modelCurrSol, modelProperties, BCsData] = ONSAS_init(materials, elements, boundaryConds, initialConds, mesh, analysisSettings, otherParams); %","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"After that the structs are used to perform the numerical time analysis","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"[matUs, loadFactorsMat, modelSolutions] = ONSAS_solve(modelCurrSol, modelProperties, BCsData);","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"\n### Verification\nThe numerical and analytic solutions are compared for the external surface (since all the elements on the same surface have the same analytic solution):","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"% global Y % Y = 2 * sigmaY0 / sqrt(3); % p0 = Y/2 * (1-a^2/b^2) p0 = Y / 2 * (1 - Ri^2 / Re^2); % Yielding pressure % pressurevals = loadFactorsMat(:, 3) * p; % cvals = zeros(length(pressurevals), 1); ubAna = zeros(length(pressurevals), 1); % % Plastic front value for i = 1:length(cvals)   p = pressurevals(i);   if i == 1     % val = fsolve(@(c)cValue(c,p,Y,a,b), a) ;     val = fsolve(@(c)cValue(c, p, Y, Ri, Re), Ri);   else     % val = fsolve(@(c)cValue(c,p,Y,a,b), cvals(i-1)) ;     val = fsolve(@(c)cValue(c, p, Y, Ri, Re), cvals(i - 1));   end   cvals(i) = val; end % % Analytic radial displacement at outer surface for i = 1:length(cvals)   p = pressure_vals(i);   if p < p0     % ubAna(i) = 2pb / ( E( b^2/a^2-1 ) ) * (1-nu^2) ;     ubAna(i) = 2 * p * Re / (E * (Re^2 / Ri^2 - 1)) * (1 - nu^2);   else     c = cvals(i);     % ubAna(i) = Yc^2/(E*b) * (1-nu^2) ;     ubAna(i) = Y * c^2 / (E * Re) * (1 - nu^2);   end end","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"\n### Plots","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"% plot parameters lw = 2.0; ms = 11; plotFontSize = 10; fig = figure; hold on; grid on; % node to plot the solution node = 5; dofX = node * 6 - 5; ubNum = matUs(dofX, :); % plot(ubNum, pressurevals, 'b-o', 'linewidth', lw, 'markersize', ms); plot(ubAna, pressurevals, 'g-x', 'linewidth', lw, 'markersize', ms); % legend ({'FEM', 'Analytic'}, 'location', 'east'); labx = xlabel('ub'); laby = ylabel('p'); tit = title('p-ub'); set(labx, 'fontsize', plotFontSize * .8); set(laby, 'fontsize', plotFontSize * .8); set(tit, 'fontsize', plotFontSize);","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"\n The numerical solution is verified for both cases:\n","category":"page"},{"location":"examples/ringPlaneStrain/","page":"Plane strain ring","title":"Plane strain ring","text":"analyticCheckTolerance = 1e-2; verifBoolean = ((numericalRi - analyticValRi) < analyticCheckTolerance) && ...                ((numericalRe - analyticValRe) < analyticCheckTolerance) && ...                ((ubNum(end) - ubAna(end)) < analyticCheckTolerance); ```","category":"page"}]
}
